@tailwind base;
@tailwind components;
@tailwind utilities;

/* Professional animations and effects */
@keyframes fadeInUp {
  from {
    opacity: 0;
    transform: translateY(30px);
  }
  to {
    opacity: 1;
    transform: translateY(0);
  }
}

@keyframes shimmer {
  0% {
    background-position: -200% 0;
  }
  100% {
    background-position: 200% 0;
  }
}

@keyframes shine {
  0% {
    transform: translateX(-100%) rotate(45deg);
  }
  100% {
    transform: translateX(100%) rotate(45deg);
  }
}

@keyframes float {
  0%, 100% {
    transform: translateY(0);
  }
  50% {
    transform: translateY(-10px);
  }
}

@keyframes pulse-glow {
  0%, 100% {
    box-shadow: 0 0 20px rgba(var(--primary), 0.3);
  }
  50% {
    box-shadow: 0 0 30px rgba(var(--primary), 0.6);
  }
}

/* Utility classes */
.animate-fadeInUp {
  animation: fadeInUp 0.8s ease-out;
}

.animate-shimmer {
  background: linear-gradient(90deg, #f0f0f0 25%, #e0e0e0 50%, #f0f0f0 75%);
  background-size: 200% 100%;
  animation: shimmer 1.5s infinite;
}

.animate-shine {
  animation: shine 0.8s ease-out;
}

.animate-float {
  animation: float 3s ease-in-out infinite;
}

.animate-pulse-glow {
  animation: pulse-glow 2s ease-in-out infinite;
}

/* Enhanced Modal responsive styles */
.modal-content {
  @apply p-3 sm:p-4 md:p-6;
  max-height: calc(100vh - 60px);
  overflow-y: auto;
}

.product-modal-content {
  @apply max-w-4xl w-full max-h-[90vh] overflow-hidden;
}

.product-modal-body {
  @apply overflow-y-auto max-h-[calc(90vh-120px)] p-3 sm:p-4 md:p-6;
}

.product-modal-grid {
  @apply grid grid-cols-1 lg:grid-cols-2 gap-4 sm:gap-6;
  min-height: 400px;
}

.product-modal-image {
  @apply w-full h-64 sm:h-80 lg:h-96 object-cover rounded-lg;
}

.customize-modal-content {
  @apply max-w-6xl w-full max-h-[95vh] overflow-hidden;
}

.customize-modal-body {
  @apply overflow-y-auto max-h-[calc(95vh-120px)] p-3 sm:p-4 md:p-6;
}

/* Fix modal choppy appearance */
.modal-override {
  @apply w-[95vw] sm:w-[90vw] md:w-[85vw] lg:w-[80vw] xl:w-[75vw] 2xl:w-[70vw];
  @apply max-w-4xl max-h-[90vh] overflow-hidden;
}

.modal-override .modal-content {
  @apply overflow-y-auto max-h-[calc(90vh-120px)] p-3 sm:p-4 md:p-6;
}

/* Enhanced responsive dialog content */
[data-radix-popper-content-wrapper] {
  @apply !w-auto !max-w-none;
}

/* Grid layout fixes */
.modal-content .grid {
  @apply grid-cols-1 lg:grid-cols-2 gap-4 sm:gap-6;
  min-height: 300px;
}

/* Button responsiveness */
.modal-buttons {
  @apply flex flex-col sm:flex-row gap-3 pt-4 border-t;
}

.modal-buttons .flex-1 {
  @apply w-full sm:w-auto;
}

/* Enhanced Modal Responsiveness */
.modal-override {
  /* Mobile-first responsive spacing */
  @apply w-[calc(100vw-16px)] sm:w-[calc(100vw-32px)] md:w-[calc(100vw-48px)] lg:w-[calc(100vw-64px)];
  @apply max-w-[95vw] sm:max-w-[90vw] md:max-w-[85vw] lg:max-w-[80vw] xl:max-w-[75vw] 2xl:max-w-[70vw];
  @apply max-h-[95vh] sm:max-h-[90vh] md:max-h-[85vh];
  @apply overflow-y-auto overflow-x-hidden;
}

/* Modal content responsive grid */
.modal-content {
  @apply space-y-4 sm:space-y-6 md:space-y-8;
}

.modal-content .grid {
  @apply grid-cols-1 lg:grid-cols-2;
  @apply gap-4 sm:gap-6 md:gap-8;
}

/* Responsive button layouts */
.modal-buttons {
  @apply flex flex-col sm:flex-row gap-3 sm:gap-4;
}

.modal-buttons .flex-1 {
  @apply w-full sm:w-auto;
}

/* Image upload area responsiveness */
.image-upload-area {
  @apply p-4 sm:p-6 md:p-8;
}

.image-preview-grid {
  @apply grid grid-cols-2 sm:grid-cols-3 md:grid-cols-4 gap-2 sm:gap-3 md:gap-4;
}

/* Form responsiveness */
.form-grid {
  @apply grid grid-cols-1 sm:grid-cols-2 gap-4 sm:gap-6;
}

.form-section {
  @apply space-y-3 sm:space-y-4 md:space-y-6;
}

/* Scrollbar hide for carousel */
.scrollbar-hide {
  -ms-overflow-style: none;
  scrollbar-width: none;
}

.scrollbar-hide::-webkit-scrollbar {
  display: none;
}

/* Grid improvements for equal heights */
.auto-rows-fr {
  grid-auto-rows: 1fr;
}

/* Professional line clamp */
.line-clamp-2 {
  display: -webkit-box;
  -webkit-line-clamp: 2;
  -webkit-box-orient: vertical;
  overflow: hidden;
}

/* Professional card improvements */
.card-glass {
  background: rgba(255, 255, 255, 0.95);
  backdrop-filter: blur(10px);
  border: 1px solid rgba(255, 255, 255, 0.2);
}

/* Enhanced grid system for perfect alignment */
.product-grid {
  display: grid;
  grid-template-columns: repeat(auto-fill, minmax(280px, 1fr));
  gap: 1.5rem;
  align-items: stretch;
}

/* Modal improvements for desktop - Force proper sizing */
.modal-override,
[data-radix-dialog-content] {
  width: 95vw !important;
  max-width: 500px !important;
  height: auto !important;
  max-height: 90vh !important;
}

/* Tablet responsive */
@media (min-width: 768px) {
  .modal-override,
  [data-radix-dialog-content] {
    width: 85vw !important;
    max-width: 700px !important;
    height: auto !important;
    max-height: 85vh !important;
  }
}

/* Desktop responsive */
@media (min-width: 1024px) {
  .modal-override,
  [data-radix-dialog-content] {
    width: 80vw !important;
    max-width: 900px !important;
  }
}

/* Large desktop responsive */
@media (min-width: 1280px) {
  .modal-override,
  [data-radix-dialog-content] {
    width: 70vw !important;
    max-width: 1100px !important;
  }
}

/* Extra large desktop */
@media (min-width: 1536px) {
  .modal-override,
  [data-radix-dialog-content] {
    width: 60vw !important;
    max-width: 1200px !important;
  }
}

@keyframes slideUpAndFade {
  from {
    opacity: 0;
    transform: translate(-50%, -48%) scale(0.96);
  }
  to {
    opacity: 1;
    transform: translate(-50%, -50%) scale(1);
  }
}

/* Professional hover effects */
.hover-lift {
  transition: all 0.3s cubic-bezier(0.4, 0, 0.2, 1);
}

.hover-lift:hover {
  transform: translateY(-8px) scale(1.02);
  box-shadow: 
    0 20px 25px -5px rgba(0, 0, 0, 0.1),
    0 10px 10px -5px rgba(0, 0, 0, 0.04),
