}

/* Professional button styling */
.btn-professional {
  position: relative;
  overflow: hidden;
  transition: all 0.3s ease;
}

.btn-professional::before {
  content: '';
  position: absolute;
  top: 0;
  left: -100%;
  width: 100%;
