.bengali-text {
  font-family: 'Kalpurush', 'SolaimanLipi', 'Noto Sans Bengali', sans-serif;
  line-height: 1.6;
  letter-spacing: 0.01em;
}

/* Improved form elements */
.form-input {
  border: 2px solid #e5e7eb;
  border-radius: 8px;
  padding: 12px 16px;
  transition: all 0.3s ease;
  font-size: 16px; /* Prevents zoom on iOS */
}

.form-input:focus {
  border-color: var(--primary);
  box-shadow: 0 0 0 3px rgba(59, 130, 246, 0.1);
  outline: none;
}

/* Enhanced carousel navigation */
.carousel-nav {
  background: rgba(255, 255, 255, 0.9);
  backdrop-filter: blur(10px);
  border: none;
  border-radius: 50%;
  width: 48px;
  height: 48px;
  display: flex;
  align-items: center;
  justify-content: center;
  transition: all 0.3s ease;
  box-shadow: 0 4px 6px -1px rgba(0, 0, 0, 0.1);
}

.carousel-nav:hover {
  background: rgba(255, 255, 255, 1);
  transform: scale(1.1);
  box-shadow: 0 10px 15px -3px rgba(0, 0, 0, 0.1);
}

.carousel-nav:disabled {
  opacity: 0.5;
  cursor: not-allowed;
  transform: none;
}

/* Professional animations */
@keyframes slideInFromLeft {
  0% {
    transform: translateX(-100%);
    opacity: 0;
  }
  100% {
    transform: translateX(0);
    opacity: 1;
  }
}

@keyframes slideInFromRight {
  0% {
    transform: translateX(100%);
    opacity: 0;
  }
  100% {
    transform: translateX(0);
    opacity: 1;
  }
}

.slide-in-left {
  animation: slideInFromLeft 0.6s ease-out;
}

.slide-in-right {
  animation: slideInFromRight 0.6s ease-out;
}

@keyframes slideDown {
  0% {
    transform: translateY(-100%);
    opacity: 0;
  }
  100% {
    transform: translateY(0);
    opacity: 1;
  }
}

.animate-slide-down {
  animation: slideDown 0.3s ease-out;
}

/* Better mobile menu close button handling */
.mobile-menu-button {
  -webkit-tap-highlight-color: transparent;
  user-select: none;
}

.mobile-menu-button:active {
  transform: scale(0.95);
}

/* Enhanced mobile experience */
@media (max-width: 1024px) {
  .mobile-optimized {
    overflow-x: hidden;
    -webkit-overflow-scrolling: touch;
    scroll-behavior: smooth;
  }

  .mobile-optimized .container {
    padding-left: 1rem;
    padding-right: 1rem;
  }

  .mobile-nav-item {
    padding: 1rem;
    border-bottom: 1px solid #f3f4f6;
    transition: all 0.2s ease;
    touch-action: manipulation;
  }

  .mobile-nav-item:active {
    background-color: #f9fafb;
    transform: scale(0.98);
  }

  .mobile-nav-item:last-child {
    border-bottom: none;
  }
}

/* Perfect swipe and gesture support */
.swipe-enabled {
  touch-action: pan-x pan-y;
  -webkit-overflow-scrolling: touch;
  overflow-scrolling: touch;
  scroll-snap-type: x mandatory;
}

.swipe-item {
  scroll-snap-align: start;
  scroll-snap-stop: always;
}

/* Perfect zoom support */
.zoom-enabled {
  touch-action: pinch-zoom;
  transition: transform 0.3s cubic-bezier(0.25, 0.46, 0.45, 0.94);
}

.zoom-enabled:hover,
.zoom-enabled:focus {
  transform: scale(1.02);
}

/* Touch-friendly buttons */
.touch-button {
  touch-action: manipulation;
  user-select: none;
  -webkit-user-select: none;
  -webkit-tap-highlight-color: transparent;
  position: relative;
  overflow: hidden;
}

/* Special handling for small close buttons */
.touch-button:not(.btn):not(.button) {
  min-height: 44px;
  min-width: 44px;
}

/* Enhanced close button animations */
.touch-button.group {
  cursor: pointer;
  will-change: transform;
}

.touch-button.group:focus {
  outline: 2px solid rgba(239, 68, 68, 0.5);
  outline-offset: 2px;
}

/* Pulse animation for close button */
@keyframes pulse-close {
  0%, 100% { 
    box-shadow: 0 0 0 0 rgba(239, 68, 68, 0.7);
  }
  50% { 
    box-shadow: 0 0 0 8px rgba(239, 68, 68, 0);
  }
}

.touch-button.group:hover {
  animation: pulse-close 1.5s infinite;
}

.touch-button:active {
  transform: scale(0.98);
  transition: transform 0.1s ease;
}

.touch-button::before {
  content: '';
  position: absolute;
  top: 50%;
  left: 50%;
  width: 0;
  height: 0;
  border-radius: 50%;
  background-color: rgba(255, 255, 255, 0.3);
  transform: translate(-50%, -50%);
  transition: width 0.3s ease, height 0.3s ease;
  pointer-events: none;
}

.touch-button:active::before {
  width: 300px;
  height: 300px;
}

/* Fix scrolling issues globally */
html, body {
  -webkit-overflow-scrolling: touch;
  overflow-scrolling: touch;
  scroll-behavior: smooth;
}

/* Perfect mobile containers */
.mobile-container {
  width: 100%;
  max-width: 100vw;
  overflow-x: hidden;
  -webkit-overflow-scrolling: touch;
  overflow-scrolling: touch;
}

/* Perfect touch targets */
button, a, [role="button"], .clickable {
  min-height: 44px;
  min-width: 44px;
  touch-action: manipulation;
  -webkit-tap-highlight-color: transparent;
}

/* Fix form inputs for mobile */
input, textarea, select {
  font-size: 16px !important;
  touch-action: manipulation;
  -webkit-appearance: none;
  appearance: none;
}

/* Perfect modal/popup handling */
.modal-open, .popup-open {
  overflow: hidden;
  position: fixed;
  width: 100%;
  height: 100%;
}

/* Improved scrollbars */
.scrollbar-hide {
  scrollbar-width: none;
  -ms-overflow-style: none;
}

.scrollbar-hide::-webkit-scrollbar {
  display: none;
}

/* Improved touch targets */
@media (max-width: 768px) {
  .touch-target {
    min-height: 44px;
    min-width: 44px;
  }

  .btn-mobile {
    padding: 0.875rem 1.5rem;
    font-size: 1rem;
    min-height: 48px;
  }

  .input-mobile {
    padding: 1rem;
    font-size: 16px; /* Prevents zoom on iOS */
    min-height: 48px;
  }
}

/* Enhanced Product Loading Animations */
@keyframes shimmer {
  0% { transform: translateX(-100%) skewX(-12deg); }
  100% { transform: translateX(200%) skewX(-12deg); }
}

.animate-shimmer {
  animation: shimmer 2s infinite;
}

/* Floating animation for loading elements */
@keyframes float {
  0%, 100% { transform: translateY(0px); }
  50% { transform: translateY(-10px); }
}

.animate-float {
  animation: float 3s ease-in-out infinite;
}

/* Pulse glow effect */
@keyframes pulse-glow {
  0%, 100% { opacity: 0.7; box-shadow: 0 0 10px rgba(59, 130, 246, 0.3); }
  50% { opacity: 1; box-shadow: 0 0 20px rgba(59, 130, 246, 0.6); }
}

.animate-pulse-glow {
  animation: pulse-glow 2s ease-in-out infinite;
}

