import { useState, useEffect, useRef } from "react";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import { MessageCircle, Send, X, Bot, User, Minimize2, Maximize2, Mic, MicOff, Volume2, VolumeX, Loader2 } from "lucide-react";
import { useQuery } from "@tanstack/react-query";
import { formatPrice, COMPANY_NAME, WHATSAPP_NUMBER } from "@/lib/constants";
import type { Product } from "@shared/schema";

interface ChatMessage {
  id: string;
  role: 'user' | 'assistant';
  content: string;
  timestamp: string;
  products?: Product[];
}

interface AIChatbotProps {
  onProductSelect?: (product: Product) => void;
}

// Business data for the AI
const BUSINESS_DATA = {
  name: "Trynex Lifestyle",
  description: "আধুনিক লাইফস্টাইল পণ্যের প্রিমিয়াম অনলাইন শপ",
  categories: ["ফ্যাশন", "ইলেকট্রনিক্স", "গিফট আইটেম", "হোম ডেকোর", "বিউটি পণ্য"],
  features: [
    "দ্রুত ডেলিভারি (ঢাকায় ২৪ ঘন্টা)",
    "নগদে পেমেন্ট",
    "বিনামূল্যে রিটার্ন পলিসি",
    "১০০% অরিজিনাল পণ্য",
    "কাস্টমাইজেশন সুবিধা"
  ],
  contact: {
    whatsapp: WHATSAPP_NUMBER,
    support: "২৪/৭ কাস্টমার সাপোর্ট",
    delivery: "ঢাকা: ৮০ টাকা, ঢাকার বাইরে: ৮০-১২০ টাকা"
  },
  policies: {
    return: "৭ দিনের মধ্যে রিটার্ন",
    warranty: "১ বছর ওয়ারেন্টি",
    payment: "বিকাশ, নগদ, ক্যাশ অন ডেলিভারি"
  }
};

export default function EnhancedAIChatbot({ onProductSelect }: AIChatbotProps) {
  const [isOpen, setIsOpen] = useState(false);
  const [isMinimized, setIsMinimized] = useState(false);
  const [messages, setMessages] = useState<ChatMessage[]>([
    {
      id: '1',
      role: 'assistant',
      content: `আসসালামু আলাইকুম! 🌟 আমি ${BUSINESS_DATA.name} এর AI সহায়ক। 

আমি আপনাকে সাহায্য করতে পারি:
• পণ্য খুঁজে দিতে এবং সুপারিশ করতে
• অর্ডার প্রক্রিয়ায় গাইড করতে
• ডেলিভারি ও পেমেন্ট সম্পর্কে তথ্য দিতে
• কাস্টমাইজেশন সহায়তা করতে
• গিফট আইটেম নির্বাচনে সাহায্য করতে
• বাংলাদেশের যেকোনো বিষয়ে আলোচনা করতে

কী খুঁজছেন? 🛍️`,
      timestamp: new Date().toLocaleTimeString('bn-BD')
    }
  ]);
  const [inputMessage, setInputMessage] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [isListening, setIsListening] = useState(false);
  const [isSpeaking, setIsSpeaking] = useState(false);
  const [conversationHistory, setConversationHistory] = useState<string[]>([]);
  const messagesEndRef = useRef<HTMLDivElement>(null);
  const recognitionRef = useRef<any>(null);

  // Get products for search functionality
  const { data: products = [] } = useQuery<Product[]>({
    queryKey: ["/api/products"],
    staleTime: 1000 * 60 * 5,
  });

  // Initialize speech recognition
  useEffect(() => {
    if ('webkitSpeechRecognition' in window || 'SpeechRecognition' in window) {
      const SpeechRecognition = (window as any).webkitSpeechRecognition || (window as any).SpeechRecognition;
      recognitionRef.current = new SpeechRecognition();
      recognitionRef.current.continuous = false;
      recognitionRef.current.interimResults = false;
      recognitionRef.current.lang = 'bn-BD';

      recognitionRef.current.onresult = (event: any) => {
        const transcript = event.results[0][0].transcript;
        setInputMessage(transcript);
        setIsListening(false);
      };

      recognitionRef.current.onerror = () => {
        setIsListening(false);
      };

      recognitionRef.current.onend = () => {
        setIsListening(false);
      };
    }
  }, []);

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
  };

  useEffect(() => {
    scrollToBottom();
  }, [messages]);

  const speakMessage = (text: string) => {
    if ('speechSynthesis' in window) {
      const utterance = new SpeechSynthesisUtterance(text);
      utterance.lang = 'bn-BD';
      utterance.rate = 0.8;
      utterance.onstart = () => setIsSpeaking(true);
      utterance.onend = () => setIsSpeaking(false);
      speechSynthesis.speak(utterance);
    }
  };

  const stopSpeaking = () => {
    if ('speechSynthesis' in window) {
      speechSynthesis.cancel();
      setIsSpeaking(false);
    }
  };

  const startListening = () => {
    if (recognitionRef.current && !isListening) {
      setIsListening(true);
      recognitionRef.current.start();
    }
  };

  const stopListening = () => {
    if (recognitionRef.current && isListening) {
      recognitionRef.current.stop();
      setIsListening(false);
    }
  };

  const getAIResponse = async (userMessage: string): Promise<string> => {
    try {
      // Input validation and sanitization
      const sanitizedMessage = userMessage.trim().substring(0, 1000);
      if (!sanitizedMessage) {
        return generateFallbackResponse('empty message');
      }

      const response = await fetch('/api/ai/chat', {
        method: 'POST',
        headers: { 
          'Content-Type': 'application/json',
          'Accept': 'application/json'
        },
        body: JSON.stringify({
          message: sanitizedMessage,
          businessData: BUSINESS_DATA,
          products: products?.slice(0, 20) || [], // Send sample products
          chatHistory: messages.slice(-6).map(msg => ({
            role: msg.role,
            content: msg.content.substring(0, 500) // Limit history content
          }))
        })
      });

      if (!response.ok) {
        console.warn('AI API failed, using fallback');
        return generateFallbackResponse(userMessage);
      }

      const data = await response.json();

      // Validate response
      if (data.reply && typeof data.reply === 'string') {
        return data.reply;
      }

      return generateFallbackResponse(userMessage);
    } catch (error) {
      console.error('AI Chat Error:', error);
      return generateFallbackResponse(userMessage);
    }
  };

  const generateFallbackResponse = (userMessage: string): string => {
    const message = userMessage.toLowerCase();

    if (message.includes('পণ্য') || message.includes('product') || message.includes('আইটেম')) {
      const randomProducts = products.slice(0, 3);
      return `আমাদের জনপ্রিয় পণ্য:\n${randomProducts.map(p => `• ${p.name} - ${formatPrice(Number(p.price))}`).join('\n')}\n\nআরো দেখতে "সব পণ্য" বলুন।`;
    }

    if (message.includes('ডেলিভারি') || message.includes('delivery')) {
      return `📦 ডেলিভারি তথ্য:\n• ঢাকায়: ৮০ টাকা (২৪ ঘন্টা)\n• ঢাকার বাইরে: ৮০-১২০ টাকা (২-৩ দিন)\n• বিনামূল্যে রিটার্ন ৭ দিনের মধ্যে`;
    }

    if (message.includes('পেমেন্ট') || message.includes('payment')) {
      return `💳 পেমেন্ট পদ্ধতি:\n• বিকাশ/নগদ\n• ক্যাশ অন ডেলিভারি\n• অনলাইন পেমেন্ট\n\nসবগুলো নিরাপদ ও সুবিধাজনক!`;
    }

    if (message.includes('যোগাযোগ') || message.includes('contact')) {
      return `📞 যোগাযোগ:\n• হোয়াটসঅ্যাপ: ${WHATSAPP_NUMBER}\n• ২৪/৭ কাস্টমার সাপোর্ট\n• তাৎক্ষণিক সহায়তার জন্য কল করুন`;
    }

    return `ধন্যবাদ! আমি ${BUSINESS_DATA.name} এর AI সহায়ক। আপনি চাইলে:\n\n• "পণ্য দেখান" - সব পণ্য দেখতে\n• "ডেলিভারি" - ডেলিভারি তথ্য\n• "পেমেন্ট" - পেমেন্ট পদ্ধতি\n• "যোগাযোগ" - কাস্টমার সাপোর্ট\n\nবলুন, আর আমি সাহায্য করব! 😊`;
  };

  const sendMessage = async () => {
    if (!inputMessage.trim() || isLoading) return;

    const userMessage: ChatMessage = {
      id: Date.now().toString(),
      role: 'user',
      content: inputMessage,
      timestamp: new Date().toLocaleTimeString('bn-BD')
    };

    setMessages(prev => [...prev, userMessage]);
    setInputMessage('');
    setIsLoading(true);

    try {
      const aiReply = await getAIResponse(inputMessage);

      const assistantMessage: ChatMessage = {
        id: (Date.now() + 1).toString(),
        role: 'assistant',
        content: aiReply,
        timestamp: new Date().toLocaleTimeString('bn-BD')
      };

      setMessages(prev => [...prev, assistantMessage]);

      // Auto-speak response if not too long
      if (aiReply.length < 200) {
        setTimeout(() => speakMessage(aiReply), 500);
      }

    } catch (error) {
      console.error('Chat error:', error);
      // Add error message to chat
      const errorMessage: ChatMessage = {
        id: (Date.now() + 1).toString(),
        role: 'assistant',
        content: generateFallbackResponse(inputMessage),
        timestamp: new Date().toLocaleTimeString('bn-BD')
      };
      setMessages(prev => [...prev, errorMessage]);
    } finally {
      setIsLoading(false);
    }
  };

  const handleKeyPress = (e: React.KeyboardEvent) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      sendMessage();
    }
  };

  if (!isOpen) {
    return (
      <Button
        onClick={() => setIsOpen(true)}
        className="fixed bottom-6 right-6 z-50 w-14 h-14 rounded-full bg-gradient-to-r from-primary to-emerald-600 hover:from-primary/90 hover:to-emerald-700 shadow-xl animate-pulse"
        size="lg"
      >
        <MessageCircle className="w-6 h-6 text-white" />
      </Button>
    );
  }

  return (
    <Card className={`fixed bottom-6 right-6 z-50 w-80 md:w-96 bg-white shadow-2xl border-0 transition-all duration-300 ${
      isMinimized ? 'h-16' : 'h-96'
    }`}>
      <CardHeader className="p-4 bg-gradient-to-r from-primary to-emerald-600 text-white rounded-t-lg">
        <div className="flex items-center justify-between">
          <div className="flex items-center space-x-2">
            <Bot className="w-5 h-5" />
            <CardTitle className="text-sm font-semibold">Trynex AI সহায়ক</CardTitle>
          </div>
          <div className="flex items-center space-x-1">
            <Button
              variant="ghost"
              size="sm"
              onClick={() => setIsMinimized(!isMinimized)}
              className="text-white hover:bg-white/20 p-1 h-auto"
            >
              {isMinimized ? <Maximize2 className="w-4 h-4" /> : <Minimize2 className="w-4 h-4" />}
            </Button>
            <Button
              variant="ghost"
              size="sm"
              onClick={() => setIsOpen(false)}
              className="text-white hover:bg-white/20 p-1 h-auto"
            >
              <X className="w-4 h-4" />
            </Button>
          </div>
        </div>
      </CardHeader>

      {!isMinimized && (
        <CardContent className="p-0 flex flex-col h-80">
          {/* Messages */}
          <div className="flex-1 overflow-y-auto p-4 space-y-3">
            {messages.map((message) => (
              <div
                key={message.id}
                className={`flex ${message.role === 'user' ? 'justify-end' : 'justify-start'}`}
              >
                <div
                  className={`max-w-[80%] p-3 rounded-lg ${
                    message.role === 'user'
                      ? 'bg-primary text-white'
                      : 'bg-gray-100 text-gray-800'
                  }`}
                >
                  <div className="text-sm whitespace-pre-wrap">{message.content}</div>
                  <div className="text-xs opacity-70 mt-1">{message.timestamp}</div>
                </div>
              </div>
            ))}
            {isLoading && (
              <div className="flex justify-start">
                <div className="bg-gray-100 p-3 rounded-lg">
                  <Loader2 className="w-4 h-4 animate-spin" />
                </div>
              </div>
            )}
            <div ref={messagesEndRef} />
          </div>

          {/* Input */}
          <div className="p-4 border-t">
            <div className="flex items-center space-x-2">
              <div className="flex-1 relative">
                <Input
                  value={inputMessage}
                  onChange={(e) => setInputMessage(e.target.value)}
                  onKeyPress={handleKeyPress}
                  placeholder="আপনার প্রশ্ন লিখুন..."
                  className="pr-20"
                  disabled={isLoading}
                />
                <div className="absolute right-2 top-1/2 -translate-y-1/2 flex items-center space-x-1">
                  <Button
                    variant="ghost"
                    size="sm"
                    onClick={isListening ? stopListening : startListening}
                    className="p-1 h-auto text-gray-500 hover:text-primary"
                  >
                    {isListening ? <MicOff className="w-4 h-4" /> : <Mic className="w-4 h-4" />}
                  </Button>
                  <Button
                    variant="ghost"
                    size="sm"
                    onClick={isSpeaking ? stopSpeaking : () => {}}
                    className="p-1 h-auto text-gray-500 hover:text-primary"
                  >
                    {isSpeaking ? <VolumeX className="w-4 h-4" /> : <Volume2 className="w-4 h-4" />}
                  </Button>
                </div>
              </div>
              <Button
                onClick={sendMessage}
                disabled={!inputMessage.trim() || isLoading}
                size="sm"
                className="bg-primary hover:bg-primary/90"
              >
                <Send className="w-4 h-4" />
              </Button>
            </div>
          </div>
        </CardContent>
      )}
    </Card>
  );
}

client/src/components/EnhancedLoadingSke.content:
import { Card, CardContent } from "@/components/ui/card";
import { Skeleton } from "@/components/ui/skeleton";
import { ShoppingCart, Heart, Eye, Star, Sparkles, TrendingUp, Gift } from "lucide-react";
import { useEffect, useState } from "react";

interface EnhancedLoadingSkeletonProps {
  count?: number;
  minimumDuration?: number; // Minimum loading time in ms
  onLoadingComplete?: () => void;
}

export default function EnhancedLoadingSkeleton({ 
  count = 6, 
  minimumDuration = 5000,
  onLoadingComplete 
}: EnhancedLoadingSkeletonProps) {
  const [loadingPhase, setLoadingPhase] = useState(0);
  const [showContent, setShowContent] = useState(false);

  useEffect(() => {
    // Phase 1: Initial connection (0-1s)
    const phase1Timer = setTimeout(() => setLoadingPhase(1), 800);

    // Phase 2: Loading products (1-2.5s)
    const phase2Timer = setTimeout(() => setLoadingPhase(2), 2000);

    // Phase 3: Optimizing display (2.5-4s)
    const phase3Timer = setTimeout(() => setLoadingPhase(3), 3500);

    // Phase 4: Finalizing (4-5s)
    const phase4Timer = setTimeout(() => setLoadingPhase(4), 4500);

    // Complete loading after minimum duration
    const completeTimer = setTimeout(() => {
      setShowContent(true);
      onLoadingComplete?.();
    }, minimumDuration);

    return () => {
      clearTimeout(phase1Timer);
      clearTimeout(phase2Timer);
      clearTimeout(phase3Timer);
      clearTimeout(phase4Timer);
      clearTimeout(completeTimer);
    };
  }, [minimumDuration, onLoadingComplete]);

  const getLoadingText = () => {
    switch (loadingPhase) {
      case 0: return "ডাটাবেস সংযোগ স্থাপন করছি...";
      case 1: return "সেরা পণ্য খুঁজে আনছি...";
      case 2: return "দাম ও স্টক আপডেট করছি...";
      case 3: return "ইমেজ অপ্টিমাইজ করছি...";
      case 4: return "প্রায় সম্পন্ন...";
      default: return "লোড হচ্ছে...";
    }
  };

  if (showContent) {
    return null; // This component hides itself after loading
  }

  return (
    <div className="space-y-8">
      {/* Loading header with animated text */}
      <div className="text-center py-4">
        <div className="flex items-center justify-center space-x-2 mb-3">
          <div className="relative">
            <div className="w-8 h-8 border-4 border-primary/30 border-t-primary rounded-full animate-spin"></div>
            <Sparkles className="w-4 h-4 text-primary absolute top-1/2 left-1/2 transform -translate-x-1/2 -translate-y-1/2 animate-pulse" />
          </div>
          <h3 className="text-lg font-semibold text-gray-700 animate-pulse">
            {getLoadingText()}
          </h3>
        </div>

        {/* Progress bar */}
        <div className="w-80 mx-auto bg-gray-200 rounded-full h-3 overflow-hidden shadow-inner">
          <div 
            className="h-full bg-gradient-to-r from-primary via-blue-500 to-purple-500 rounded-full transition-all duration-800 ease-out shadow-lg"
            style={{ 
              width: `${Math.min(100, (loadingPhase + 1) * 20)}%`,
              animation: 'shimmer 1.5s infinite'
            }}
          ></div>
        </div>

        <p className="text-sm text-gray-500 mt-3 animate-pulse">
          {loadingPhase < 3 ? "আমাদের প্রিমিয়াম কালেকশন প্রস্তুত করছি..." : "সবকিছু প্রস্তুত!"}
        </p>

        <div className="flex items-center justify-center space-x-4 mt-4">
          <div className="text-xs text-gray-400 flex items-center space-x-1">
            <div className={`w-2 h-2 rounded-full ${loadingPhase >= 1 ? 'bg-green-400' : 'bg-gray-300'} transition-colors duration-300`}></div>
            <span>ডাটাবেস</span>
          </div>
          <div className="text-xs text-gray-400 flex items-center space-x-1">
            <div className={`w-2 h-2 rounded-full ${loadingPhase >= 2 ? 'bg-blue-400' : 'bg-gray-300'} transition-colors duration-300`}></div>
            <span>পণ্য</span>
          </div>
          <div className="text-xs text-gray-400 flex items-center space-x-1">
            <div className={`w-2 h-2 rounded-full ${loadingPhase >= 3 ? 'bg-purple-400' : 'bg-gray-300'} transition-colors duration-300`}></div>
            <span>ইমেজ</span>
          </div>
          <div className="text-xs text-gray-400 flex items-center space-x-1">
            <div className={`w-2 h-2 rounded-full ${loadingPhase >= 4 ? 'bg-orange-400' : 'bg-gray-300'} transition-colors duration-300`}></div>
            <span>সম্পন্ন</span>
          </div>
        </div>
      </div>

      {/* Enhanced product grid skeleton */}
      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-6">
        {Array.from({ length: count }).map((_, index) => (
          <Card 
            key={index} 
            className="group relative overflow-hidden shadow-lg hover:shadow-xl transition-all duration-500 animate-pulse"
            style={{
              animationDelay: `${index * 200}ms`,
              animationDuration: '2s'
            }}
          >
            <div className="relative">
              {/* Advanced shimmer image skeleton */}
              <div className="aspect-[4/5] bg-gradient-to-br from-gray-200 via-gray-100 to-gray-200 relative overflow-hidden">
                {/* Animated shimmer overlay */}
                <div className="absolute inset-0 bg-gradient-to-r from-transparent via-white/40 to-transparent animate-shimmer"></div>

                {/* Floating icons animation */}
                <div className="absolute inset-0 flex items-center justify-center">
                  <div className="relative">
                    <ShoppingCart 
                      className="w-8 h-8 text-gray-400 animate-bounce" 
                      style={{ animationDelay: `${index * 100}ms` }}
                    />
                    <Heart 
                      className="w-4 h-4 text-red-300 absolute -top-2 -right-2 animate-ping" 
                      style={{ animationDelay: `${index * 150}ms` }}
                    />
                  </div>
                </div>

                {/* Corner badge skeleton */}
                <div className="absolute top-3 left-3">
                  <div className="px-2 py-1 bg-primary/20 rounded-full">
                    <div className="flex items-center space-x-1">
                      <Star className="w-3 h-3 text-primary/60 animate-pulse" />
                      <Skeleton className="h-3 w-8 bg-primary/30" />
                    </div>
                  </div>
                </div>

                {/* Stock indicator */}
                <div className="absolute top-3 right-3">
                  <Skeleton className="h-6 w-16 bg-green-200 rounded-full" />
                </div>
              </div>
            </div>

            <CardContent className="p-4 space-y-3">
              {/* Product title with typewriter effect */}
              <div className="space-y-2">
                <Skeleton className="h-5 w-full bg-gradient-to-r from-gray-200 to-gray-300" />
                <Skeleton className="h-4 w-3/4 bg-gradient-to-r from-gray-200 to-gray-300" />
              </div>

              {/* Price and rating skeleton */}
              <div className="flex items-center justify-between">
                <div className="flex items-center space-x-2">
                  <TrendingUp className="w-4 h-4 text-green-400 animate-pulse" />
                  <Skeleton className="h-6 w-20 bg-gradient-to-r from-primary/20 to-primary/40" />
                </div>
                <div className="flex items-center space-x-1">
                  {[...Array(5)].map((_, i) => (
                    <Star 
                      key={i} 
                      className="w-3 h-3 text-yellow-300 animate-pulse" 
                      style={{ animationDelay: `${i * 100}ms` }}
                    />
                  ))}
                </div>
              </div>

              {/* Action buttons skeleton */}
              <div className="space-y-2">
                <div className="flex space-x-2">
                  <Skeleton className="h-9 flex-1 bg-gradient-to-r from-primary/30 to-primary/50 rounded-lg">
                    <div className="flex items-center justify-center h-full">
                      <ShoppingCart className="w-4 h-4 text-primary/60 animate-pulse" />
                    </div>
                  </Skeleton>
                  <Skeleton className="h-9 w-9 bg-gray-200 rounded-lg">
                    <div className="flex items-center justify-center h-full">
                      <Eye className="w-4 h-4 text-gray-400 animate-pulse" />
                    </div>
                  </Skeleton>
                </div>

                <Skeleton className="h-9 w-full bg-gradient-to-r from-purple-200 to-purple-300 rounded-lg">
                  <div className="flex items-center justify-center h-full">
                    <Gift className="w-4 h-4 text-purple-400 animate-bounce" />
                  </div>
                </Skeleton>
              </div>

              {/* Feature indicators */}
              <div className="flex items-center justify-between pt-2">
                <div className="flex space-x-2">
                  <Skeleton className="h-4 w-4 bg-green-200 rounded-full animate-pulse" />
                  <Skeleton className="h-3 w-16 bg-green-200" />
                </div>
                <Skeleton className="h-3 w-20 bg-blue-200" />
              </div>
            </CardContent>
          </Card>
        ))}
      </div>

      {/* Bottom loading indicators */}
      <div className="text-center space-y-4">
        <div className="flex items-center justify-center space-x-4">
          <div className="flex space-x-1">
            {[...Array(3)].map((_, i) => (
              <div
                key={i}
                className="w-2 h-2 bg-primary rounded-full animate-bounce"
                style={{ animationDelay: `${i * 200}ms` }}
              ></div>
            ))}
          </div>
          <span className="text-sm text-gray-500">
            {count} টি পণ্য লোড হচ্ছে
          </span>
        </div>

        <div className="flex items-center justify-center space-x-6 text-xs text-gray-400">
          <div className="flex items-center space-x-1">
            <div className="w-2 h-2 bg-green-400 rounded-full animate-ping"></div>
            <span>সর্বোচ্চ মানের পণ্য</span>
          </div>
          <div className="flex items-center space-x-1">
            <div className="w-2 h-2 bg-blue-400 rounded-full animate-ping" style={{ animationDelay: '500ms' }}></div>
            <span>দ্রুত ডেলিভারি</span>
          </div>
          <div className="flex items-center space-x-1">
            <div className="w-2 h-2 bg-purple-400 rounded-full animate-ping" style={{ animationDelay: '1000ms' }}></div>
            <span>সাশ্রয়ী দাম</span>
          </div>
        </div>
      </div>
    </div>
  );
}

