  const handleViewProduct = (e: React.MouseEvent) => {
    e.preventDefault();
    e.stopPropagation();
    onViewProduct(product);
  };

  const handleCustomize = (e: React.MouseEvent) => {
    e.preventDefault();
    e.stopPropagation();
    if (onCustomize) {
      onCustomize(product);
    }
  };

  const rating = 4.5; // Mock rating - replace with actual rating
  const reviewCount = 42; // Mock review count

  return (
    <Card 
      className={`group cursor-pointer transition-all duration-300 hover:shadow-lg mobile-transition overflow-hidden product-card ${className}`}
      onMouseEnter={() => setIsHovered(true)}
      onMouseLeave={() => setIsHovered(false)}
