export const trackAddToCart = (productId: string, productName: string, value: number) => {
  // Google Analytics
  trackEvent('add_to_cart', 'ecommerce', productName, value);

  // Facebook Pixel
  trackFBEvent('AddToCart', {
    value: value,
    currency: 'BDT',
    content_ids: [productId],
