        {/* Action Buttons */}
        <div className="absolute top-3 right-3 space-y-2 opacity-0 group-hover:opacity-100 transition-opacity duration-300">
          <Button
            onClick={handleToggleFavorite}
            size="sm"
            variant="outline"
