import { useState, useEffect } from "react";
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Textarea } from "@/components/ui/textarea";
import { Label } from "@/components/ui/label";
import { Switch } from "@/components/ui/switch";
import { Badge } from "@/components/ui/badge";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { Dialog, DialogContent, DialogDescription, DialogHeader, DialogTitle, DialogTrigger } from "@/components/ui/dialog";
import { AlertDialog, AlertDialogAction, AlertDialogCancel, AlertDialogContent, AlertDialogDescription, AlertDialogFooter, AlertDialogHeader, AlertDialogTitle, AlertDialogTrigger } from "@/components/ui/alert-dialog";
import { PlusCircle, Edit, Trash2, Eye, Calendar, Tag } from "lucide-react";
import { useToast } from "@/hooks/use-toast";
import { z } from "zod";

const blogSchema = z.object({
  title: z.string().min(1, "শিরোনাম প্রয়োজন"),
  content: z.string().min(1, "কন্টেন্ট প্রয়োজন"),
  excerpt: z.string().min(1, "সারাংশ প্রয়োজন"),
  author: z.string().min(1, "লেখকের নাম প্রয়োজন"),
  status: z.enum(["draft", "published"]),
  is_featured: z.boolean(),
  tags: z.string().optional(),
  meta_title: z.string().optional(),
  meta_description: z.string().optional(),
});

type BlogPost = {
  id: number;
  title: string;
  content: string;
  excerpt: string;
  author: string;
  status: "draft" | "published";
  is_featured: boolean;
  tags?: string;
  meta_title?: string;
  meta_description?: string;
  created_at: string;
  updated_at: string;
};

export default function BlogManagement() {
  const { toast } = useToast();
  const [blogs, setBlogs] = useState<BlogPost[]>([]);
  const [loading, setLoading] = useState(true);
  const [editingBlog, setEditingBlog] = useState<BlogPost | null>(null);
  const [isDialogOpen, setIsDialogOpen] = useState(false);
  const [formData, setFormData] = useState({
    title: "",
    content: "",
    excerpt: "",
    author: "",
    status: "draft" as const,
    is_featured: false,
    tags: "",
    meta_title: "",
    meta_description: "",
  });

  const fetchBlogs = async () => {
    try {
      const response = await fetch('/api/blogs');
      if (response.ok) {
        const data = await response.json();
        setBlogs(data);
      }
    } catch (error) {
      console.error('Error fetching blogs:', error);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchBlogs();
  }, []);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();

    try {
      blogSchema.parse(formData);

      const method = editingBlog ? 'PUT' : 'POST';
      const url = editingBlog ? `/api/blogs/${editingBlog.id}` : '/api/blogs';

      const response = await fetch(url, {
        method,
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(formData),
      });

      if (response.ok) {
        toast({
          title: "সফল!",
          description: editingBlog ? "ব্লগ পোস্ট আপডেট করা হয়েছে" : "নতুন ব্লগ পোস্ট তৈরি করা হয়েছে",
        });

        resetForm();
        setIsDialogOpen(false);
        fetchBlogs();
      } else {
        throw new Error('Failed to save blog post');
      }
    } catch (error) {
      if (error instanceof z.ZodError) {
        toast({
          title: "ত্রুটি",
          description: error.errors[0].message,
          variant: "destructive",
        });
      } else {
        toast({
          title: "ত্রুটি",
          description: "ব্লগ পোস্ট সেভ করতে সমস্যা হয়েছে",
          variant: "destructive",
        });
      }
    }
  };

  const handleEdit = (blog: BlogPost) => {
    setEditingBlog(blog);
    setFormData({
      title: blog.title,
      content: blog.content,
      excerpt: blog.excerpt,
      author: blog.author,
      status: blog.status,
      is_featured: blog.is_featured,
      tags: blog.tags || "",
      meta_title: blog.meta_title || "",
      meta_description: blog.meta_description || "",
    });
    setIsDialogOpen(true);
  };

  const handleDelete = async (id: number) => {
    try {
      const response = await fetch(`/api/blogs/${id}`, {
        method: 'DELETE',
      });

      if (response.ok) {
        toast({
          title: "সফল!",
          description: "ব্লগ পোস্ট ডিলিট করা হয়েছে",
        });
        fetchBlogs();
      } else {
        throw new Error('Failed to delete blog post');
      }
    } catch (error) {
      toast({
        title: "ত্রুটি",
        description: "ব্লগ পোস্ট ডিলিট করতে সমস্যা হয়েছে",
        variant: "destructive",
      });
    }
  };

  const resetForm = () => {
    setFormData({
      title: "",
      content: "",
      excerpt: "",
      author: "",
      status: "draft",
      is_featured: false,
      tags: "",
      meta_title: "",
      meta_description: "",
    });
    setEditingBlog(null);
  };

  const formatDate = (dateString: string) => {
    return new Date(dateString).toLocaleDateString('bn-BD');
  };

  if (loading) {
    return (
      <div className="flex items-center justify-center h-64">
        <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-primary"></div>
      </div>
    );
  }

  return (
    <div className="space-y-6">
      <div className="flex justify-between items-center">
        <div>
          <h2 className="text-2xl font-bold">ব্লগ ম্যানেজমেন্ট</h2>
          <p className="text-gray-600">ব্লগ পোস্ট তৈরি এবং পরিচালনা করুন</p>
        </div>

        <Dialog open={isDialogOpen} onOpenChange={setIsDialogOpen}>
          <DialogTrigger asChild>
            <Button onClick={resetForm}>
              <PlusCircle className="w-4 h-4 mr-2" />
              নতুন পোস্ট
            </Button>
          </DialogTrigger>

          <DialogContent className="max-w-4xl max-h-[90vh] overflow-y-auto">
            <DialogHeader>
              <DialogTitle>{editingBlog ? "পোস্ট এডিট করুন" : "নতুন পোস্ট তৈরি করুন"}</DialogTitle>
              <DialogDescription>
                ব্লগ পোস্টের তথ্য পূরণ করুন
              </DialogDescription>
            </DialogHeader>

            <form onSubmit={handleSubmit} className="space-y-4">
              <div className="grid grid-cols-2 gap-4">
                <div>
                  <Label htmlFor="title">শিরোনাম *</Label>
                  <Input
                    id="title"
                    value={formData.title}
                    onChange={(e) => setFormData({ ...formData, title: e.target.value })}
                    placeholder="ব্লগ পোস্টের শিরোনাম"
                    required
                  />
                </div>

                <div>
                  <Label htmlFor="author">লেখক *</Label>
                  <Input
                    id="author"
                    value={formData.author}
                    onChange={(e) => setFormData({ ...formData, author: e.target.value })}
                    placeholder="লেখকের নাম"
                    required
                  />
                </div>
              </div>

              <div>
                <Label htmlFor="excerpt">সারাংশ *</Label>
                <Textarea
                  id="excerpt"
                  value={formData.excerpt}
                  onChange={(e) => setFormData({ ...formData, excerpt: e.target.value })}
                  placeholder="পোস্টের সংক্ষিপ্ত বিবরণ"
                  rows={3}
                  required
                />
              </div>

              <div>
                <Label htmlFor="content">কন্টেন্ট *</Label>
                <Textarea
                  id="content"
                  value={formData.content}
                  onChange={(e) => setFormData({ ...formData, content: e.target.value })}
                  placeholder="পোস্টের বিস্তারিত কন্টেন্ট"
                  rows={10}
                  required
                />
              </div>

              <div className="grid grid-cols-2 gap-4">
                <div>
                  <Label htmlFor="status">স্ট্যাটাস</Label>
                  <Select value={formData.status} onValueChange={(value: "draft" | "published") => setFormData({ ...formData, status: value })}>
                    <SelectTrigger>
                      <SelectValue />
                    </SelectTrigger>
                    <SelectContent>
                      <SelectItem value="draft">খসড়া</SelectItem>
                      <SelectItem value="published">প্রকাশিত</SelectItem>
                    </SelectContent>
                  </Select>
                </div>

                <div>
                  <Label htmlFor="tags">ট্যাগ</Label>
                  <Input
                    id="tags"
                    value={formData.tags}
                    onChange={(e) => setFormData({ ...formData, tags: e.target.value })}
                    placeholder="কমা দিয়ে আলাদা করুন"
                  />
                </div>
              </div>

              <div className="flex items-center space-x-2">
                <Switch
                  id="featured"
                  checked={formData.is_featured}
                  onCheckedChange={(checked) => setFormData({ ...formData, is_featured: checked })}
                />
                <Label htmlFor="featured">ফিচার্ড পোস্ট</Label>
              </div>

              <div className="grid grid-cols-2 gap-4">
                <div>
                  <Label htmlFor="meta_title">মেটা টাইটেল</Label>
                  <Input
                    id="meta_title"
                    value={formData.meta_title}
                    onChange={(e) => setFormData({ ...formData, meta_title: e.target.value })}
                    placeholder="SEO টাইটেল"
                  />
                </div>

                <div>
                  <Label htmlFor="meta_description">মেটা বিবরণ</Label>
                  <Textarea
                    id="meta_description"
                    value={formData.meta_description}
                    onChange={(e) => setFormData({ ...formData, meta_description: e.target.value })}
                    placeholder="SEO বিবরণ"
                    rows={2}
                  />
                </div>
              </div>

              <div className="flex justify-end space-x-2 pt-4">
                <Button type="button" variant="outline" onClick={() => setIsDialogOpen(false)}>
                  বাতিল
                </Button>
                <Button type="submit">
                  {editingBlog ? "আপডেট করুন" : "তৈরি করুন"}
                </Button>
              </div>
            </form>
          </DialogContent>
        </Dialog>
      </div>

      {/* Blog Posts List */}
      <div className="grid gap-4">
        {blogs.length === 0 ? (
          <Card>
            <CardContent className="text-center py-12">
              <p className="text-gray-500">কোনো ব্লগ পোস্ট নেই</p>
            </CardContent>
          </Card>
        ) : (
          blogs.map((blog) => (
            <Card key={blog.id}>
              <CardContent className="p-6">
                <div className="flex justify-between items-start mb-4">
                  <div className="flex-1">
                    <div className="flex items-center gap-2 mb-2">
                      <h3 className="text-lg font-semibold">{blog.title}</h3>
                      {blog.is_featured && (
                        <Badge variant="secondary">ফিচার্ড</Badge>
                      )}
                      <Badge variant={blog.status === 'published' ? 'default' : 'secondary'}>
                        {blog.status === 'published' ? 'প্রকাশিত' : 'খসড়া'}
                      </Badge>
                    </div>

                    <p className="text-gray-600 text-sm mb-2">{blog.excerpt}</p>

                    <div className="flex items-center text-xs text-gray-500 space-x-4">
                      <span className="flex items-center">
                        <Calendar className="w-3 h-3 mr-1" />
                        {formatDate(blog.created_at)}
                      </span>
                      <span>লেখক: {blog.author}</span>
                      {blog.tags && (
                        <span className="flex items-center">
                          <Tag className="w-3 h-3 mr-1" />
                          {blog.tags}
                        </span>
                      )}
                    </div>
                  </div>

                  <div className="flex items-center space-x-2">
                    <Button size="sm" variant="outline" onClick={() => window.open(`/blog/${blog.id}`, '_blank')}>
                      <Eye className="w-4 h-4" />
                    </Button>
                    <Button size="sm" variant="outline" onClick={() => handleEdit(blog)}>
                      <Edit className="w-4 h-4" />
                    </Button>
                    <AlertDialog>
                      <AlertDialogTrigger asChild>
                        <Button size="sm" variant="outline">
                          <Trash2 className="w-4 h-4" />
                        </Button>
                      </AlertDialogTrigger>
                      <AlertDialogContent>
                        <AlertDialogHeader>
                          <AlertDialogTitle>নিশ্চিত করুন</AlertDialogTitle>
                          <AlertDialogDescription>
                            আপনি কি এই ব্লগ পোস্টটি ডিলিট করতে চান? এই কাজটি পূর্বাবস্থায় ফেরানো যাবে না।
                          </AlertDialogDescription>
                        </AlertDialogHeader>
                        <AlertDialogFooter>
                          <AlertDialogCancel>বাতিল</AlertDialogCancel>
                          <AlertDialogAction onClick={() => handleDelete(blog.id)}>
                            ডিলিট করুন
                          </AlertDialogAction>
                        </AlertDialogFooter>
                      </AlertDialogContent>
                    </AlertDialog>
                  </div>
                </div>
              </CardContent>
            </Card>
          ))
        )}
      </div>
    </div>
  );
}

client/src/components/admin/order-detail.content:
import { useState, useEffect } from "react";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import { Button } from "@/components/ui/button";
import { Separator } from "@/components/ui/separator";
import { Textarea } from "@/components/ui/textarea";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { 
  Package, 
  User, 
  MapPin, 
  Phone, 
  CreditCard, 
  Image as ImageIcon,
  FileText,
  Truck,
  Calendar,
  DollarSign,
  Eye,
  Download,
  Palette,
  Type,
  Settings,
  CheckCircle,
  Clock,
  AlertCircle
} from "lucide-react";
import { formatPrice } from "@/lib/constants";
import type { Order } from "@shared/schema";

interface OrderDetailsEnhancedProps {
  order: Order;
  onUpdateStatus: (orderId: string, status: string) => void;
  onAddNote: (orderId: string, note: string) => void;
}

export default function OrderDetailsEnhanced({ 
  order, 
  onUpdateStatus, 
  onAddNote 
}: OrderDetailsEnhancedProps) {
  const [newNote, setNewNote] = useState("");
  const [selectedStatus, setSelectedStatus] = useState(order.status);
  const [showCustomizationDetails, setShowCustomizationDetails] = useState(true);

  const orderItems = typeof order.items === 'string' 
    ? JSON.parse(order.items) 
    : order.items || [];

  const paymentInfo = typeof order.payment_info === 'string'
    ? JSON.parse(order.payment_info)
    : order.payment_info || {};

  const handleStatusUpdate = () => {
    if (selectedStatus !== order.status) {
      onUpdateStatus(order.id, selectedStatus);
    }
  };

  const handleAddNote = () => {
    if (newNote.trim()) {
      onAddNote(order.id, newNote);
      setNewNote("");
    }
  };

  const getStatusColor = (status: string) => {
    switch (status) {
      case 'pending': return 'bg-yellow-100 text-yellow-800';
      case 'confirmed': return 'bg-blue-100 text-blue-800';
      case 'processing': return 'bg-purple-100 text-purple-800';
      case 'shipped': return 'bg-indigo-100 text-indigo-800';
      case 'delivered': return 'bg-green-100 text-green-800';
      case 'cancelled': return 'bg-red-100 text-red-800';
      default: return 'bg-gray-100 text-gray-800';
    }
  };

  const getStatusBangla = (status: string) => {
    switch (status) {
      case 'pending': return 'অপেক্ষমাণ';
      case 'confirmed': return 'নিশ্চিত';
      case 'processing': return 'প্রক্রিয়াধীন';
      case 'shipped': return 'পাঠানো হয়েছে';
      case 'delivered': return 'ডেলিভার হয়েছে';
      case 'cancelled': return 'বাতিল';
      default: return status;
    }
  };

  return (
    <div className="space-y-6">
      {/* Order Header */}
      <Card>
        <CardHeader>
          <div className="flex items-start justify-between">
            <div>
              <CardTitle className="flex items-center gap-2">
                <Package className="w-5 h-5" />
                অর্ডার #{order.tracking_id}
              </CardTitle>
              <p className="text-sm text-gray-600 mt-1">
                অর্ডারের তারিখ: {new Date(order.created_at).toLocaleDateString('bn-BD')}
              </p>
            </div>
            <Badge className={getStatusColor(order.status)}>
              {getStatusBangla(order.status)}
            </Badge>
          </div>
        </CardHeader>
        <CardContent className="space-y-4">
          {/* Status Update */}
          <div className="flex items-center gap-4">
            <Select value={selectedStatus} onValueChange={setSelectedStatus}>
              <SelectTrigger className="w-48">
                <SelectValue />
              </SelectTrigger>
              <SelectContent>
                <SelectItem value="pending">অপেক্ষমাণ</SelectItem>
                <SelectItem value="confirmed">নিশ্চিত</SelectItem>
                <SelectItem value="processing">প্রক্রিয়াধীন</SelectItem>
                <SelectItem value="shipped">পাঠানো হয়েছে</SelectItem>
                <SelectItem value="delivered">ডেলিভার হয়েছে</SelectItem>
                <SelectItem value="cancelled">বাতিল</SelectItem>
              </SelectContent>
            </Select>
            <Button 
              onClick={handleStatusUpdate}
              disabled={selectedStatus === order.status}
              size="sm"
            >
              স্ট্যাটাস আপডেট করুন
            </Button>
          </div>

          {/* Order Summary */}
          <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
            <div className="flex items-center gap-2">
              <DollarSign className="w-4 h-4 text-green-600" />
              <div>
                <p className="text-sm text-gray-600">মোট পরিমাণ</p>
                <p className="font-semibold">{formatPrice(order.total)}</p>
              </div>
            </div>
            <div className="flex items-center gap-2">
              <Truck className="w-4 h-4 text-blue-600" />
              <div>
                <p className="text-sm text-gray-600">ডেলিভারি ফি</p>
                <p className="font-semibold">{formatPrice(order.delivery_fee || 0)}</p>
              </div>
            </div>
            <div className="flex items-center gap-2">
              <CreditCard className="w-4 h-4 text-purple-600" />
              <div>
                <p className="text-sm text-gray-600">পেমেন্ট</p>
                <p className="font-semibold">
                  {paymentInfo.method === 'cod' ? 'ক্যাশ অন ডেলিভারি' : paymentInfo.method?.toUpperCase()}
                </p>
              </div>
            </div>
          </div>
        </CardContent>
      </Card>

      {/* Customer Information */}
      <Card>
        <CardHeader>
          <CardTitle className="flex items-center gap-2">
            <User className="w-5 h-5" />
            গ্রাহকের তথ্য
          </CardTitle>
        </CardHeader>
        <CardContent className="space-y-4">
          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
            <div>
              <div className="flex items-center gap-2 mb-2">
                <User className="w-4 h-4 text-gray-500" />
                <span className="text-sm font-medium">নাম</span>
              </div>
              <p className="text-gray-900">{order.customer_name}</p>
            </div>
            <div>
              <div className="flex items-center gap-2 mb-2">
                <Phone className="w-4 h-4 text-gray-500" />
                <span className="text-sm font-medium">ফোন</span>
              </div>
              <p className="text-gray-900">{order.phone}</p>
            </div>
          </div>

          <div>
            <div className="flex items-center gap-2 mb-2">
              <MapPin className="w-4 h-4 text-gray-500" />
              <span className="text-sm font-medium">ঠিকানা</span>
            </div>
            <p className="text-gray-900">
              {order.address}<br />
              {order.thana}, {order.district}
            </p>
          </div>

          {paymentInfo.delivery_instructions && (
            <div>
              <div className="flex items-center gap-2 mb-2">
                <FileText className="w-4 h-4 text-gray-500" />
                <span className="text-sm font-medium">ডেলিভারি নির্দেশনা</span>
              </div>
              <p className="text-gray-900 bg-gray-50 p-3 rounded">
                {paymentInfo.delivery_instructions}
              </p>
            </div>
          )}
        </CardContent>
      </Card>

      {/* Order Items with Customization Details */}
      <Card>
        <CardHeader>
          <CardTitle className="flex items-center gap-2">
            <Package className="w-5 h-5" />
            অর্ডার আইটেম ও কাস্টমাইজেশন
          </CardTitle>
        </CardHeader>
        <CardContent>
          <div className="space-y-6">
            {orderItems.map((item: any, index: number) => (
              <div key={index} className="border rounded-lg p-4">
                <div className="flex gap-4">
                  {/* Product Image */}
                  <div className="w-20 h-20 bg-gray-100 rounded-lg overflow-hidden flex-shrink-0">
                    <img
                      src={item.image_url || "/placeholder.jpg"}
                      alt={item.product_name || item.name}
                      className="w-full h-full object-cover"
                    />
                  </div>

                  {/* Product Info */}
                  <div className="flex-1">
                    <h4 className="font-semibold text-lg">{item.product_name || item.name}</h4>
                    <div className="flex items-center gap-4 mt-2">
                      <span className="text-sm text-gray-600">পরিমাণ: {item.quantity}</span>
                      <span className="text-sm text-gray-600">দাম: {formatPrice(item.price)}</span>
                      <span className="font-semibold">মোট: {formatPrice(item.price * item.quantity)}</span>
                    </div>
                  </div>
                </div>

                {/* Customization Details */}
                {item.customization && (
                  <div className="mt-4 pt-4 border-t">
                    <div className="flex items-center justify-between mb-3">
                      <h5 className="font-medium flex items-center gap-2">
                        <Settings className="w-4 h-4" />
                        কাস্টমাইজেশন বিবরণ
                      </h5>
                      <Button
                        variant="ghost"
                        size="sm"
                        onClick={() => setShowCustomizationDetails(!showCustomizationDetails)}
                      >
                        {showCustomizationDetails ? 'লুকান' : 'দেখান'}
                      </Button>
                    </div>

                    {showCustomizationDetails && (
                      <div className="space-y-3">
                        {/* Basic Customization */}
                        <div className="grid grid-cols-2 md:grid-cols-3 gap-4 text-sm">
                          {item.customization.size && (
                            <div>
                              <span className="text-gray-600">সাইজ:</span>
                              <span className="ml-2 font-medium">{item.customization.size}</span>
                            </div>
                          )}
                          {item.customization.color && (
                            <div className="flex items-center">
                              <span className="text-gray-600">রং:</span>
                              <div className="ml-2 flex items-center gap-2">
                                <span className="font-medium">{item.customization.color}</span>
                                <Palette className="w-4 h-4 text-gray-500" />
                              </div>
                            </div>
                          )}
                          {item.customization.material && (
                            <div>
                              <span className="text-gray-600">উপাদান:</span>
                              <span className="ml-2 font-medium">{item.customization.material}</span>
                            </div>
                          )}
                          {item.customization.printArea && (
                            <div>
                              <span className="text-gray-600">প্রিন্ট এরিয়া:</span>
                              <span className="ml-2 font-medium">{item.customization.printArea}</span>
                            </div>
                          )}
                          {item.customization.printQuality && (
                            <div>
                              <span className="text-gray-600">প্রিন্ট কোয়ালিটি:</span>
                              <span className="ml-2 font-medium">{item.customization.printQuality}</span>
                            </div>
                          )}
                          {item.customization.deliveryPreference && (
                            <div>
                              <span className="text-gray-600">ডেলিভারি:</span>
                              <span className="ml-2 font-medium">{item.customization.deliveryPreference}</span>
                            </div>
                          )}
                        </div>

                        {/* Custom Text */}
                        {item.customization.customText && (
                          <div className="bg-blue-50 p-3 rounded">
                            <div className="flex items-center gap-2 mb-2">
                              <Type className="w-4 h-4 text-blue-600" />
                              <span className="font-medium text-blue-800">কাস্টম টেক্সট</span>
                            </div>
                            <p className="text-blue-900">{item.customization.customText}</p>
                          </div>
                        )}

                        {/* Special Instructions */}
                        {item.customization.specialInstructions && (
                          <div className="bg-yellow-50 p-3 rounded">
                            <div className="flex items-center gap-2 mb-2">
                              <AlertCircle className="w-4 h-4 text-yellow-600" />
                              <span className="font-medium text-yellow-800">বিশেষ নির্দেশনা</span>
                            </div>
                            <p className="text-yellow-900">{item.customization.specialInstructions}</p>
                          </div>
                        )}

                        {/* Additional Requests */}
                        {item.customization.additionalRequests && (
                          <div className="bg-green-50 p-3 rounded">
                            <div className="flex items-center gap-2 mb-2">
                              <FileText className="w-4 h-4 text-green-600" />
                              <span className="font-medium text-green-800">অতিরিক্ত অনুরোধ</span>
                            </div>
                            <p className="text-green-900">{item.customization.additionalRequests}</p>
                          </div>
                        )}

                        {/* Custom Image */}
                        {item.customization.customImage && (
                          <div className="bg-purple-50 p-3 rounded">
                            <div className="flex items-center gap-2 mb-3">
                              <ImageIcon className="w-4 h-4 text-purple-600" />
                              <span className="font-medium text-purple-800">আপলোড করা ছবি</span>
                            </div>
                            <div className="flex items-center gap-4">
                              <img
                                src={item.customization.customImage}
                                alt="Custom uploaded image"
                                className="w-24 h-24 object-cover rounded border"
                              />
                              <div className="flex gap-2">
                                <Button
                                  size="sm"
                                  variant="outline"
                                  onClick={() => window.open(item.customization.customImage, '_blank')}
                                >
                                  <Eye className="w-4 h-4 mr-1" />
                                  দেখুন
                                </Button>
                                <Button
                                  size="sm"
                                  variant="outline"
                                  onClick={() => {
                                    const link = document.createElement('a');
                                    link.href = item.customization.customImage;
                                    link.download = `custom-image-${item.product_name}-${Date.now()}.jpg`;
                                    link.click();
                                  }}
                                >
                                  <Download className="w-4 h-4 mr-1" />
                                  ডাউনলোড
                                </Button>
                              </div>
                            </div>
                          </div>
                        )}
                      </div>
                    )}
                  </div>
                )}
              </div>
            ))}
          </div>
        </CardContent>
      </Card>

      {/* Admin Notes */}
      <Card>
        <CardHeader>
          <CardTitle className="flex items-center gap-2">
            <FileText className="w-5 h-5" />
            অ্যাডমিন নোট
          </CardTitle>
        </CardHeader>
        <CardContent className="space-y-4">
          <div className="space-y-2">
            <Textarea
              placeholder="অর্ডার সম্পর্কে নোট যোগ করুন..."
              value={newNote}
              onChange={(e) => setNewNote(e.target.value)}
              rows={3}
            />
            <Button onClick={handleAddNote} disabled={!newNote.trim()}>
              নোট যোগ করুন
            </Button>
          </div>

          {/* Existing Notes */}
          {order.notes && (
            <div className="space-y-2">
              <h4 className="font-medium">পূর্ববর্তী নোট:</h4>
              <div className="bg-gray-50 p-3 rounded">
                <pre className="whitespace-pre-wrap text-sm">{order.notes}</pre>
              </div>
            </div>
          )}
        </CardContent>
      </Card>
    </div>
  );
}

client/src/components/admin/pages-manage.content:
import { useState } from "react";
import { useQuery, useMutation, useQueryClient } from "@tanstack/react-query";
import { Plus, Edit, Trash2, FileText, Eye, Globe } from "lucide-react";
import { Button } from "@/components/ui/button";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import { Input } from "@/components/ui/input";
import { Textarea } from "@/components/ui/textarea";
import { Switch } from "@/components/ui/switch";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogTrigger } from "@/components/ui/dialog";
import { Form, FormControl, FormField, FormItem, FormLabel, FormMessage } from "@/components/ui/form";
import { useForm } from "react-hook-form";
import { zodResolver } from "@hookform/resolvers/zod";
import { z } from "zod";
import { apiRequest } from "@/lib/queryClient";
import { format } from "date-fns";
import type { Page } from "@shared/schema";

const pageSchema = z.object({
  slug: z.string().min(1, "স্লাগ প্রয়োজন").regex(/^[a-z0-9-]+$/, "শুধুমাত্র ছোট হাতের অক্ষর, সংখ্যা এবং হাইফেন ব্যবহার করুন"),
  title: z.string().min(1, "শিরোনাম প্রয়োজন"),
  content: z.string().min(1, "কন্টেন্ট প্রয়োজন"),
  is_active: z.boolean(),
});

type PageFormData = z.infer<typeof pageSchema>;

interface PageFormProps {
  page?: Page;
  onClose: () => void;
}

function PageForm({ page, onClose }: PageFormProps) {
  const queryClient = useQueryClient();

  const form = useForm<PageFormData>({
    resolver: zodResolver(pageSchema),
    defaultValues: {
      slug: page?.slug || "",
      title: page?.title || "",
      content: page?.content || "",
      is_active: page?.is_active ?? true,
    },
  });

  const createPageMutation = useMutation({
    mutationFn: (data: PageFormData) => apiRequest('/api/pages', {
      method: 'POST',
      body: JSON.stringify(data),
    }),
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['/api/pages'] });
      onClose();
    },
  });

  const updatePageMutation = useMutation({
    mutationFn: (data: PageFormData) => apiRequest(`/api/pages/${page?.slug}`, {
      method: 'PUT',
      body: JSON.stringify(data),
    }),
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['/api/pages'] });
      onClose();
    },
  });

  const onSubmit = (data: PageFormData) => {
    if (page) {
      updatePageMutation.mutate(data);
    } else {
      createPageMutation.mutate(data);
    }
  };

  return (
    <Form {...form}>
      <form onSubmit={form.handleSubmit(onSubmit)} className="space-y-6">
        <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
          <FormField
            control={form.control}
            name="slug"
            render={({ field }) => (
              <FormItem>
                <FormLabel>স্লাগ (URL) *</FormLabel>
                <FormControl>
                  <Input placeholder="terms-conditions" {...field} disabled={!!page} />
                </FormControl>
                <p className="text-xs text-muted-foreground">
                  {!!page ? "স্লাগ পরিবর্তন করা যাবে না" : "URL-এ ব্যবহৃত হবে। যেমন: terms-conditions"}
                </p>
                <FormMessage />
              </FormItem>
            )}
          />

          <FormField
            control={form.control}
            name="title"
            render={({ field }) => (
              <FormItem>
                <FormLabel>পেজের শিরোনাম *</FormLabel>
                <FormControl>
                  <Input placeholder="শর্তাবলী" {...field} />
                </FormControl>
                <FormMessage />
              </FormItem>
            )}
          />
        </div>

        <FormField
          control={form.control}
          name="content"
          render={({ field }) => (
            <FormItem>
              <FormLabel>পেজ কন্টেন্ট *</FormLabel>
              <FormControl>
                <Textarea 
                  placeholder="পেজের বিস্তারিত কন্টেন্ট লিখুন। HTML ট্যাগ ব্যবহার করা যাবে।"
                  className="min-h-[300px]"
                  {...field} 
                />
              </FormControl>
              <p className="text-xs text-muted-foreground">
                HTML ট্যাগ সাপোর্ট করে। যেমন: &lt;h2&gt;, &lt;p&gt;, &lt;ul&gt;, &lt;li&gt; ইত্যাদি।
              </p>
              <FormMessage />
            </FormItem>
          )}
        />

        <FormField
          control={form.control}
          name="is_active"
          render={({ field }) => (
            <FormItem className="flex flex-row items-center justify-between rounded-lg border p-4">
              <div className="space-y-0.5">
                <FormLabel className="text-base">সক্রিয় পেজ</FormLabel>
                <p className="text-sm text-muted-foreground">
                  পেজটি ওয়েবসাইটে দেখানো হবে কি না
                </p>
              </div>
              <FormControl>
                <Switch
                  checked={field.value}
                  onCheckedChange={field.onChange}
                />
              </FormControl>
            </FormItem>
          )}
        />

        <div className="flex justify-end space-x-2">
          <Button type="button" variant="outline" onClick={onClose}>
            বাতিল
          </Button>
          <Button 
            type="submit" 
            disabled={createPageMutation.isPending || updatePageMutation.isPending}
          >
            {page ? "আপডেট করুন" : "তৈরি করুন"}
          </Button>
        </div>
      </form>
    </Form>
  );
}

export default function PagesManagement() {
  const [isDialogOpen, setIsDialogOpen] = useState(false);
  const [editingPage, setEditingPage] = useState<Page | undefined>();
  const queryClient = useQueryClient();

  const { data: pages = [], isLoading } = useQuery({
    queryKey: ["/api/pages"],
  });

  const deletePageMutation = useMutation({
    mutationFn: (slug: string) => apiRequest(`/api/pages/${slug}`, {
      method: 'DELETE',
    }),
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['/api/pages'] });
    },
  });

  const handleEdit = (page: Page) => {
    setEditingPage(page);
    setIsDialogOpen(true);
  };

  const handleDelete = (slug: string) => {
    if (confirm('আপনি কি নিশ্চিত যে এই পেজ মুছে ফেলতে চান?')) {
      deletePageMutation.mutate(slug);
    }
  };

  const handleCloseDialog = () => {
    setIsDialogOpen(false);
    setEditingPage(undefined);
  };

  const defaultPages = [
    {
      slug: 'terms-conditions',
