      {/* Floating particles effect */}
      <motion.div 
        animate={{ 
          opacity: [0, 1, 0],
          scale: [0.8, 1, 0.8]
        }}
        transition={{ 
          duration: 4,
          repeat: Infinity,
          delay: index * 0.5
        }}
        className="absolute top-2 left-2 w-2 h-2 bg-blue-400 rounded-full"
      />
      <motion.div 
        animate={{ 
          opacity: [0, 1, 0],
          scale: [0.8, 1, 0.8]
        }}
        transition={{ 
          duration: 4,
          repeat: Infinity,
          delay: index * 0.5 + 1
        }}
        className="absolute bottom-4 right-4 w-1.5 h-1.5 bg-green-400 rounded-full"
      />
    </motion.div>
  );
}

