          <div>
            <Label htmlFor="site_description">সাইটের বর্ণনা</Label>
            <Textarea
              id="site_description"
              value={settings.site_description}
              onChange={(e) => setSettings(prev => ({ ...prev, site_description: e.target.value }))}
              placeholder="আপনার সাইট সম্পর্কে বলুন"
              rows={3}
