import { useState } from 'react';
import { Dialog, DialogContent, DialogHeader, DialogTitle } from '@/components/ui/dialog';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import { useToast } from '@/hooks/use-toast';
import { useMutation, useQueryClient } from '@tanstack/react-query';
import { apiRequest } from '@/lib/queryClient';
import { Loader2, User, Phone, Lock, UserPlus, MapPin } from 'lucide-react';

interface UserRegistrationProps {
  isOpen: boolean;
  onClose: () => void;
  onLoginClick: () => void;
}

interface RegistrationData {
  firstName: string;
  lastName: string;
  phone: string;
  password: string;
  confirmPassword: string;
  address: string;
}

export default function UserRegistration({ isOpen, onClose, onLoginClick }: UserRegistrationProps) {
  const { toast } = useToast();
  const queryClient = useQueryClient();

  const [formData, setFormData] = useState<RegistrationData>({
    firstName: '',
    lastName: '',
    phone: '',
    password: '',
    confirmPassword: '',
    address: ''
  });

  const [errors, setErrors] = useState<Partial<RegistrationData>>({});

  const registrationMutation = useMutation({
    mutationFn: async (data: RegistrationData) => {
      const response = await apiRequest('POST', '/api/auth/register', {
        firstName: data.firstName.trim(),
        lastName: data.lastName.trim(),
        phone: data.phone.trim(),
        password: data.password,
        address: data.address.trim()
      });

      if (!response.ok) {
        const errorData = await response.json();
        throw new Error(errorData.message || 'রেজিস্ট্রেশন ব্যর্থ হয়েছে');
      }

      return response.json();
    },
    onSuccess: (data) => {
      toast({
        title: "রেজিস্ট্রেশন সফল!",
        description: "আপনার অ্যাকাউন্ট তৈরি হয়েছে। এখন লগইন করুন।",
      });

      // Clear form
      setFormData({
        firstName: '',
        lastName: '',
        phone: '',
        password: '',
        confirmPassword: '',
        address: ''
      });
      setErrors({});

      // Close registration and open login
      onClose();
      onLoginClick();

      // Refresh user data
      queryClient.invalidateQueries({ queryKey: ['/api/users'] });
    },
    onError: (error: any) => {
      toast({
        title: "রেজিস্ট্রেশন ব্যর্থ",
        description: error.message || "অ্যাকাউন্ট তৈরি করতে সমস্যা হয়েছে। আবার চেষ্টা করুন।",
        variant: "destructive",
      });
    }
  });

  const validateForm = (): boolean => {
    const newErrors: Partial<RegistrationData> = {};

    if (!formData.firstName.trim()) {
      newErrors.firstName = 'নাম প্রয়োজন';
    }

    if (!formData.phone.trim()) {
      newErrors.phone = 'মোবাইল নম্বর প্রয়োজন';
    } else if (!/^01[3-9]\d{8}$/.test(formData.phone.trim())) {
      newErrors.phone = 'সঠিক মোবাইল নম্বর দিন (01xxxxxxxxx)';
    }

    if (!formData.password) {
      newErrors.password = 'পাসওয়ার্ড প্রয়োজন';
    } else if (formData.password.length < 6) {
      newErrors.password = 'পাসওয়ার্ড কমপক্ষে ৬ অক্ষরের হতে হবে';
    }

    if (formData.password !== formData.confirmPassword) {
      newErrors.confirmPassword = 'পাসওয়ার্ড মিলছে না';
    }

    if (!formData.address.trim()) {
      newErrors.address = 'ঠিকানা প্রয়োজন';
    }

    setErrors(newErrors);
    return Object.keys(newErrors).length === 0;
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();

    if (!validateForm()) {
      return;
    }

    registrationMutation.mutate(formData);
  };

  const handleInputChange = (field: keyof RegistrationData, value: string) => {
    setFormData(prev => ({ ...prev, [field]: value }));

    // Clear error when user starts typing
    if (errors[field]) {
      setErrors(prev => ({ ...prev, [field]: undefined }));
    }
  };

  return (
    <Dialog open={isOpen} onOpenChange={onClose}>
      <DialogContent className="w-[95vw] max-w-md mx-auto p-6">
        <DialogHeader>
          <DialogTitle className="text-xl font-bold text-center text-gray-800 flex items-center justify-center gap-2">
            <UserPlus className="w-6 h-6 text-primary" />
            নতুন অ্যাকাউন্ট তৈরি করুন
          </DialogTitle>
        </DialogHeader>

        <form onSubmit={handleSubmit} className="space-y-4">
          <div className="grid grid-cols-2 gap-3">
            <div>
              <Label htmlFor="firstName" className="text-sm font-medium">
                নাম *
              </Label>
              <Input
                id="firstName"
                type="text"
                value={formData.firstName}
                onChange={(e) => handleInputChange('firstName', e.target.value)}
                placeholder="নাম"
                className={errors.firstName ? 'border-red-500' : ''}
              />
              {errors.firstName && (
                <p className="text-red-500 text-xs mt-1">{errors.firstName}</p>
              )}
            </div>

            <div>
              <Label htmlFor="lastName" className="text-sm font-medium">
                পদবী
              </Label>
              <Input
                id="lastName"
                type="text"
                value={formData.lastName}
                onChange={(e) => handleInputChange('lastName', e.target.value)}
                placeholder="পদবী"
              />
            </div>
          </div>

          <div>
            <Label htmlFor="phone" className="text-sm font-medium">
              মোবাইল নম্বর *
            </Label>
            <div className="relative">
              <Phone className="absolute left-3 top-1/2 transform -translate-y-1/2 w-4 h-4 text-gray-400" />
              <Input
                id="phone"
                type="tel"
                value={formData.phone}
                onChange={(e) => handleInputChange('phone', e.target.value)}
                placeholder="01xxxxxxxxx"
                className={`pl-10 ${errors.phone ? 'border-red-500' : ''}`}
                maxLength={11}
              />
            </div>
            {errors.phone && (
              <p className="text-red-500 text-xs mt-1">{errors.phone}</p>
            )}
          </div>

          <div>
            <Label htmlFor="address" className="text-sm font-medium">
              ঠিকানা *
            </Label>
            <div className="relative">
              <MapPin className="absolute left-3 top-1/2 transform -translate-y-1/2 w-4 h-4 text-gray-400" />
              <Input
                id="address"
                type="text"
                value={formData.address}
                onChange={(e) => handleInputChange('address', e.target.value)}
                placeholder="বাড়ির ঠিকানা"
                className={`pl-10 ${errors.address ? 'border-red-500' : ''}`}
              />
            </div>
            {errors.address && (
              <p className="text-red-500 text-xs mt-1">{errors.address}</p>
            )}
          </div>

          <div>
            <Label htmlFor="password" className="text-sm font-medium">
              পাসওয়ার্ড *
            </Label>
            <div className="relative">
              <Lock className="absolute left-3 top-1/2 transform -translate-y-1/2 w-4 h-4 text-gray-400" />
              <Input
                id="password"
                type="password"
                value={formData.password}
                onChange={(e) => handleInputChange('password', e.target.value)}
                placeholder="পাসওয়ার্ড"
                className={`pl-10 ${errors.password ? 'border-red-500' : ''}`}
              />
            </div>
            {errors.password && (
              <p className="text-red-500 text-xs mt-1">{errors.password}</p>
            )}
          </div>

          <div>
            <Label htmlFor="confirmPassword" className="text-sm font-medium">
              পাসওয়ার্ড নিশ্চিত করুন *
            </Label>
            <div className="relative">
              <Lock className="absolute left-3 top-1/2 transform -translate-y-1/2 w-4 h-4 text-gray-400" />
              <Input
                id="confirmPassword"
                type="password"
                value={formData.confirmPassword}
                onChange={(e) => handleInputChange('confirmPassword', e.target.value)}
                placeholder="পাসওয়ার্ড আবার লিখুন"
                className={`pl-10 ${errors.confirmPassword ? 'border-red-500' : ''}`}
              />
            </div>
            {errors.confirmPassword && (
              <p className="text-red-500 text-xs mt-1">{errors.confirmPassword}</p>
            )}
          </div>

          <div className="space-y-3 pt-2">
            <Button
              type="submit"
              className="w-full bg-primary hover:bg-primary/90"
              disabled={registrationMutation.isPending}
            >
              {registrationMutation.isPending ? (
                <>
                  <Loader2 className="w-4 h-4 mr-2 animate-spin" />
                  অ্যাকাউন্ট তৈরি হচ্ছে...
                </>
              ) : (
                <>
                  <UserPlus className="w-4 h-4 mr-2" />
                  অ্যাকাউন্ট তৈরি করুন
                </>
              )}
            </Button>

            <div className="text-center">
              <p className="text-sm text-gray-600">
                ইতিমধ্যে অ্যাকাউন্ট আছে?{' '}
                <button
                  type="button"
                  onClick={() => {
                    onClose();
                    onLoginClick();
                  }}
                  className="text-primary hover:underline font-medium"
                >
                  লগইন করুন
                </button>
              </p>
            </div>
          </div>
        </form>
      </DialogContent>
    </Dialog>
  );
}

client/src/components/admin/mobile-order.content:
import { useState } from 'react';
import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogDescription } from '@/components/ui/dialog';
import { Button } from '@/components/ui/button';
import { Badge } from '@/components/ui/badge';
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card';
import { Separator } from '@/components/ui/separator';
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from '@/components/ui/select';
// import { ScrollArea } from '@/components/ui/scroll-area';
import { 
  Package, 
  User, 
  MapPin, 
  Phone, 
  Calendar, 
  DollarSign, 
  Truck,
  CheckCircle,
  Clock,
  AlertCircle,
  Edit,
  Eye,
  X,
  Copy,
  MessageSquare
} from 'lucide-react';
import { formatPrice } from '@/lib/constants';
import { useToast } from '@/hooks/use-toast';

interface OrderItem {
  id: string;
  name: string;
  price: number;
  quantity: number;
  customization?: {
    text?: string;
    color?: string;
    design?: string;
  };
}

interface Order {
  id: string;
  tracking_id: string;
  customer_name: string;
  district: string;
  thana: string;
  address: string;
  phone: string;
  status: "pending" | "confirmed" | "processing" | "shipped" | "delivered" | "cancelled";
  items: OrderItem[];
  total: string;
  created_at: string;
  payment_info?: {
    method: string;
    transaction_id?: string;
    amount: number;
    advance_paid?: number;
  };
}

interface MobileOrderModalProps {
  order: Order | null;
  isOpen: boolean;
  onClose: () => void;
  onStatusUpdate?: (orderId: string, newStatus: string) => void;
}

export default function MobileOrderModal({ 
  order, 
  isOpen, 
  onClose, 
  onStatusUpdate 
}: MobileOrderModalProps) {
  const { toast } = useToast();
  const [selectedStatus, setSelectedStatus] = useState(order?.status || 'pending');

  if (!order) return null;

  const orderItems = typeof order.items === 'string' 
    ? JSON.parse(order.items) 
    : order.items || [];

  const paymentInfo = typeof order.payment_info === 'string'
    ? JSON.parse(order.payment_info)
    : order.payment_info || {};

  const getStatusColor = (status: string) => {
    switch (status) {
      case 'pending': return 'bg-yellow-100 text-yellow-800 border-yellow-200';
      case 'confirmed': return 'bg-blue-100 text-blue-800 border-blue-200';
      case 'processing': return 'bg-purple-100 text-purple-800 border-purple-200';
      case 'shipped': return 'bg-indigo-100 text-indigo-800 border-indigo-200';
      case 'delivered': return 'bg-green-100 text-green-800 border-green-200';
      case 'cancelled': return 'bg-red-100 text-red-800 border-red-200';
      default: return 'bg-gray-100 text-gray-800 border-gray-200';
    }
  };

  const getStatusIcon = (status: string) => {
    switch (status) {
      case 'pending': return <Clock className="w-4 h-4" />;
      case 'confirmed': return <CheckCircle className="w-4 h-4" />;
      case 'processing': return <Package className="w-4 h-4" />;
      case 'shipped': return <Truck className="w-4 h-4" />;
      case 'delivered': return <CheckCircle className="w-4 h-4" />;
      case 'cancelled': return <AlertCircle className="w-4 h-4" />;
      default: return <Clock className="w-4 h-4" />;
    }
  };

  const getStatusText = (status: string) => {
    switch (status) {
      case 'pending': return 'অপেক্ষমান';
      case 'confirmed': return 'নিশ্চিত';
      case 'processing': return 'প্রক্রিয়াকরণ';
      case 'shipped': return 'পাঠানো হয়েছে';
      case 'delivered': return 'ডেলিভার';
      case 'cancelled': return 'বাতিল';
      default: return status;
    }
  };

  const copyToClipboard = (text: string, label: string) => {
    navigator.clipboard.writeText(text);
    toast({
      title: "কপি হয়েছে",
      description: `${label} ক্লিপবোর্ডে কপি করা হয়েছে`,
    });
  };

  const handleStatusUpdate = () => {
    if (selectedStatus !== order.status && onStatusUpdate) {
      onStatusUpdate(order.id, selectedStatus);
      toast({
        title: "স্ট্যাটাস আপডেট",
        description: "অর্ডার স্ট্যাটাস সফলভাবে আপডেট করা হয়েছে",
      });
    }
  };

  const openWhatsApp = () => {
    const message = `আপনার অর্ডার: ${order.tracking_id}\nস্ট্যাটাস: ${getStatusText(order.status)}\nমোট: ${formatPrice(parseFloat(order.total))}`;
    const url = `https://wa.me/88${order.phone.replace(/^0/, '')}?text=${encodeURIComponent(message)}`;
    window.open(url, '_blank');
  };

  return (
    <Dialog open={isOpen} onOpenChange={onClose}>
      <DialogContent className="w-[95vw] max-w-4xl max-h-[95vh] p-0 gap-0 overflow-hidden">
        <DialogHeader className="p-4 sm:p-6 bg-gradient-to-r from-blue-50 to-indigo-50 border-b">
          <div className="flex items-center justify-between">
            <div>
              <DialogTitle className="text-lg sm:text-xl font-bold text-gray-800">
                অর্ডার বিস্তারিত
              </DialogTitle>
              <DialogDescription className="text-sm text-gray-600 mt-1">
                ট্র্যাকিং ID: {order.tracking_id}
              </DialogDescription>
            </div>
            <Button
              variant="ghost"
              size="sm"
              onClick={onClose}
              className="h-8 w-8 p-0"
            >
              <X className="w-4 h-4" />
            </Button>
          </div>
        </DialogHeader>

        <div className="flex-1 h-[calc(95vh-120px)] overflow-y-auto">
          <div className="p-4 sm:p-6 space-y-4 sm:space-y-6">
            {/* Order Status Card */}
            <Card>
              <CardHeader className="pb-3">
                <CardTitle className="text-base flex items-center gap-2">
                  {getStatusIcon(order.status)}
                  অর্ডার স্ট্যাটাস
                </CardTitle>
              </CardHeader>
              <CardContent className="space-y-4">
                <div className="flex flex-col sm:flex-row gap-3">
                  <Badge className={`${getStatusColor(order.status)} px-3 py-1 text-sm font-medium border flex items-center gap-2 w-fit`}>
                    {getStatusIcon(order.status)}
                    {getStatusText(order.status)}
                  </Badge>
                  <div className="text-sm text-gray-500">
                    {new Date(order.created_at).toLocaleDateString('bn-BD', {
                      year: 'numeric',
                      month: 'long',
                      day: 'numeric',
                      hour: '2-digit',
                      minute: '2-digit'
                    })}
                  </div>
                </div>

                <div className="grid grid-cols-1 sm:grid-cols-2 gap-3">
                  <Select value={selectedStatus} onValueChange={setSelectedStatus}>
                    <SelectTrigger>
                      <SelectValue placeholder="স্ট্যাটাস পরিবর্তন করুন" />
                    </SelectTrigger>
                    <SelectContent>
                      <SelectItem value="pending">অপেক্ষমান</SelectItem>
                      <SelectItem value="confirmed">নিশ্চিত</SelectItem>
                      <SelectItem value="processing">প্রক্রিয়াকরণ</SelectItem>
                      <SelectItem value="shipped">পাঠানো হয়েছে</SelectItem>
                      <SelectItem value="delivered">ডেলিভার</SelectItem>
                      <SelectItem value="cancelled">বাতিল</SelectItem>
                    </SelectContent>
                  </Select>

                  <Button
                    onClick={handleStatusUpdate}
                    disabled={selectedStatus === order.status}
                    className="w-full"
                    size="sm"
                  >
                    <Edit className="w-4 h-4 mr-2" />
                    স্ট্যাটাস আপডেট
                  </Button>
                </div>
              </CardContent>
            </Card>

            {/* Customer Information */}
            <Card>
              <CardHeader className="pb-3">
                <CardTitle className="text-base flex items-center gap-2">
                  <User className="w-4 h-4" />
                  গ্রাহক তথ্য
                </CardTitle>
              </CardHeader>
              <CardContent className="space-y-3">
                <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
                  <div>
                    <p className="text-sm font-medium text-gray-600">নাম</p>
                    <p className="text-sm font-semibold">{order.customer_name}</p>
                  </div>
                  <div>
                    <p className="text-sm font-medium text-gray-600">ফোন</p>
                    <div className="flex items-center gap-2">
                      <p className="text-sm font-semibold">{order.phone}</p>
                      <Button
                        variant="ghost"
                        size="sm"
                        onClick={() => copyToClipboard(order.phone, 'ফোন নম্বর')}
                        className="h-6 w-6 p-0"
                      >
                        <Copy className="w-3 h-3" />
                      </Button>
                    </div>
                  </div>
                </div>

                <div>
                  <p className="text-sm font-medium text-gray-600 mb-1">ঠিকানা</p>
                  <div className="flex items-start gap-2">
                    <MapPin className="w-4 h-4 text-gray-400 mt-0.5 flex-shrink-0" />
                    <div className="text-sm">
                      <p>{order.address}</p>
                      <p className="text-gray-500">{order.thana}, {order.district}</p>
                    </div>
                  </div>
                </div>

                <Button
                  onClick={openWhatsApp}
                  className="w-full bg-green-600 hover:bg-green-700"
                  size="sm"
                >
                  <MessageSquare className="w-4 h-4 mr-2" />
                  WhatsApp এ যোগাযোগ
                </Button>
              </CardContent>
            </Card>

            {/* Order Items */}
            <Card>
              <CardHeader className="pb-3">
                <CardTitle className="text-base flex items-center gap-2">
                  <Package className="w-4 h-4" />
                  অর্ডার আইটেম ({orderItems.length}টি)
                </CardTitle>
              </CardHeader>
              <CardContent>
                <div className="space-y-3">
                  {orderItems.map((item: OrderItem, index: number) => (
                    <div key={index} className="p-3 border rounded-lg bg-gray-50">
                      <div className="flex justify-between items-start gap-3">
                        <div className="flex-1 min-w-0">
                          <h4 className="font-medium text-sm">{item.name}</h4>
                          {item.customization && (
                            <div className="mt-1 text-xs text-gray-600 space-y-1">
                              {item.customization.text && (
                                <p>কাস্টম টেক্সট: {item.customization.text}</p>
                              )}
                              {item.customization.color && (
                                <p>রং: {item.customization.color}</p>
                              )}
                              {item.customization.design && (
                                <p>ডিজাইন: {item.customization.design}</p>
                              )}
                            </div>
                          )}
                        </div>
                        <div className="text-right flex-shrink-0">
                          <p className="text-sm font-medium">
                            {item.quantity} × {formatPrice(item.price)}
                          </p>
                          <p className="text-sm font-bold text-primary">
                            {formatPrice(item.quantity * item.price)}
                          </p>
                        </div>
                      </div>
                    </div>
                  ))}
                </div>
              </CardContent>
            </Card>

            {/* Payment Information */}
            <Card>
              <CardHeader className="pb-3">
                <CardTitle className="text-base flex items-center gap-2">
                  <DollarSign className="w-4 h-4" />
                  পেমেন্ট তথ্য
                </CardTitle>
              </CardHeader>
              <CardContent className="space-y-3">
                <div className="grid grid-cols-2 gap-4 text-sm">
                  <div>
                    <p className="text-gray-600">পেমেন্ট মেথড</p>
                    <p className="font-medium">{paymentInfo.method || 'ক্যাশ অন ডেলিভারি'}</p>
                  </div>
                  {paymentInfo.transaction_id && (
                    <div>
                      <p className="text-gray-600">ট্রানজেকশন ID</p>
                      <div className="flex items-center gap-1">
                        <p className="font-medium text-xs">{paymentInfo.transaction_id}</p>
                        <Button
                          variant="ghost"
                          size="sm"
                          onClick={() => copyToClipboard(paymentInfo.transaction_id, 'ট্রানজেকশন ID')}
                          className="h-5 w-5 p-0"
                        >
                          <Copy className="w-3 h-3" />
                        </Button>
                      </div>
                    </div>
                  )}
                </div>

                <Separator />

                <div className="space-y-2">
                  <div className="flex justify-between text-sm">
                    <span>সাবটোটাল</span>
                    <span>{formatPrice(parseFloat(order.total))}</span>
                  </div>
                  <div className="flex justify-between text-sm">
                    <span>ডেলিভারি চার্জ</span>
                    <span>বিনামূল্যে</span>
                  </div>
                  <Separator />
                  <div className="flex justify-between font-bold text-base">
                    <span>মোট</span>
                    <span className="text-primary">{formatPrice(parseFloat(order.total))}</span>
                  </div>
                </div>
              </CardContent>
            </Card>
          </div>
        </div>
      </DialogContent>
    </Dialog>
  );
}

client/src/components/new-popup-offer.ts.content:
import { useState, useEffect } from "react";
import { useQuery } from "@tanstack/react-query";
import { X, Gift, Tag } from "lucide-react";
import { Button } from "@/components/ui/button";
import { Link } from "wouter";
import type { Offer } from "@shared/schema";

export default function NewPopupOffer() {
  const [isOpen, setIsOpen] = useState(false);
  const [hasShown, setHasShown] = useState(false);

  // Load popup offers
  const { data: offers = [] } = useQuery<Offer[]>({
    queryKey: ["/api/offers"],
  });

  const activePopupOffer = offers.find(offer => offer.active && offer.is_popup);

  useEffect(() => {
    if (activePopupOffer && !hasShown) {
      const timer = setTimeout(() => {
        setIsOpen(true);
        setHasShown(true);
      }, activePopupOffer.popup_delay || 3000);

      return () => clearTimeout(timer);
    }
  }, [activePopupOffer, hasShown]);

  if (!activePopupOffer || !isOpen) return null;

  return (
    <div 
      className="fixed inset-0 z-[99999] bg-black/60 backdrop-blur-sm flex items-center justify-center p-6"
      style={{ 
        position: 'fixed',
        top: 0,
        left: 0,
        right: 0,
        bottom: 0,
        height: '100vh',
        width: '100vw',
        zIndex: 99999
      }}
      onClick={(e) => {
        // Close when clicking outside the modal
        if (e.target === e.currentTarget) {
          setIsOpen(false);
        }
      }}
    >
      <div 
        className="relative bg-white rounded-3xl shadow-2xl max-w-sm w-full mx-auto animate-in zoom-in-95 duration-500"
        style={{ 
          position: 'relative',
          zIndex: 100000,
          maxHeight: '90vh',
          overflow: 'auto',
          margin: '20px' // Ensure space around the modal for the close button
        }}
        onClick={(e) => e.stopPropagation()} // Prevent closing when clicking inside modal
      >
        {/* Close Button */}
        <button
          onClick={() => setIsOpen(false)}
          className="absolute -top-4 -right-4 w-12 h-12 bg-gray-900 hover:bg-gray-800 text-white rounded-full flex items-center justify-center shadow-xl transition-all duration-200 hover:scale-105 z-[100001]"
          style={{
            position: 'absolute',
            top: '-16px',
            right: '-16px'
          }}
          data-testid="button-close-popup"
        >
          <X className="w-6 h-6" />
        </button>

        {/* Header with gradient */}
        <div className="bg-gradient-to-br from-green-500 to-green-600 rounded-t-3xl p-6 text-center">
          <div className="w-16 h-16 mx-auto bg-white/20 rounded-full flex items-center justify-center mb-4">
            <Gift className="w-8 h-8 text-white" />
          </div>
          <h2 className="text-2xl font-bold text-white mb-2">
            🎉 স্বাগতম অফার!
          </h2>
          <p className="text-green-100 text-sm">
            ১৫০০+ টাকার অর্ডারে বিশেষ ছাড়
          </p>
        </div>

        {/* Content */}
        <div className="p-6 text-center">
          <div className="mb-6">
            <div className="inline-flex items-center gap-2 bg-orange-50 px-4 py-2 rounded-full border border-orange-200 mb-4">
              <Tag className="w-4 h-4 text-orange-600" />
              <span className="font-bold text-orange-800">TRYNEX15</span>
            </div>

            <div className="text-3xl font-bold text-green-600 mb-2">
              ১৫% ছাড়
            </div>

            <p className="text-gray-600 text-sm leading-relaxed">
              ১৫০০ টাকা বা তার বেশি অর্ডারে <strong>TRYNEX15</strong> কোড ব্যবহার করুন
            </p>
          </div>

          {/* Action Buttons */}
          <div className="space-y-3">
            <Link href="/products">
              <Button 
                className="w-full h-12 bg-gradient-to-r from-green-600 to-green-700 hover:from-green-700 hover:to-green-800 text-white font-bold text-lg rounded-2xl shadow-lg hover:shadow-xl transition-all duration-200"
                onClick={() => setIsOpen(false)}
                data-testid="button-accept-offer"
              >
                এখনই কিনুন
              </Button>
            </Link>

            <Button 
              variant="ghost" 
              className="w-full h-10 text-gray-500 hover:text-gray-700 hover:bg-gray-50 text-sm"
              onClick={() => setIsOpen(false)}
              data-testid="button-dismiss-offer"
            >
              পরে দেখব
            </Button>
          </div>

          {/* Fine print */}
          <p className="text-xs text-gray-400 mt-4">
            * শর্ত প্রযোজ্য। সীমিত সময়ের জন্য।
          </p>
        </div>
      </div>
    </div>
  );
}

