            style={{ 
              touchAction: 'pan-y',
              WebkitOverflowScrolling: 'touch',
              WebkitTapHighlightColor: 'transparent',
              position: 'relative'
            }}
            data-testid="popup-content"
          >
            {/* Close Button - Perfectly Positioned */}
            <button
              onClick={closePopup}
