      screenWidth: width,
      screenHeight: height,
      orientation: width > height ? 'landscape' : 'portrait',
      pixelRatio,
    });
  }, []);

  // Initialize device detection
  useEffect(() => {
    detectDevice();

    const handleResize = () => {
      setTimeout(detectDevice, 100);
