  background-size: 200% 100%;
  animation: shimmer 1.5s infinite;
}

/* Responsive grid improvements */
.xs\\:grid-cols-2 {
  @media (min-width: 480px) {
    grid-template-columns: repeat(2, minmax(0, 1fr));
  }
}
`;

