                      <div>
                        <Label htmlFor="customImage">কাস্টম ছবি আপলোড করুন</Label>
                        <div className="mt-2">
                          <input
                            id="customImage"
                            type="file"
                            accept="image/*"
                            onChange={handleFileUpload}
                            className="hidden"
                          />
                          <Button
                            variant="outline"
                            onClick={() => document.getElementById('customImage')?.click()}
                            className="w-full"
                          >
                            <Upload className="w-4 h-4 mr-2" />
                            ছবি নির্বাচন করুন
                          </Button>
                        </div>
                        {selectedFile && (
                          <p className="text-sm text-gray-600 mt-2">
                            নির্বাচিত: {selectedFile.name}
                          </p>
                        )}
                      </div>
                    </TabsContent>

                    <TabsContent value="instructions" className="space-y-4">
                      <div>
                        <Label htmlFor="instructions">বিশেষ নির্দেশনা</Label>
                        <Textarea
                          id="instructions"
                          placeholder="আপনার বিশেষ নির্দেশনা লিখুন..."
                          value={customization.instructions || ''}
                          onChange={(e) => setCustomization(prev => ({ ...prev, instructions: e.target.value }))}
                          rows={4}
                        />
                      </div>
                    </TabsContent>
                  </Tabs>
                </CardContent>
              </Card>

              {/* Position Controls */}
              <Card>
                <CardHeader>
                  <CardTitle>অবস্থান নিয়ন্ত্রণ</CardTitle>
                </CardHeader>
                <CardContent>
                  <div className="grid grid-cols-2 gap-4">
                    <div>
                      <Label htmlFor="positionX">X অবস্থান (%)</Label>
                      <Input
                        id="positionX"
                        type="number"
                        min="0"
                        max="100"
                        value={customization.position.x}
                        onChange={(e) => setCustomization(prev => ({
                          ...prev,
                          position: { ...prev.position, x: Number(e.target.value) }
                        }))}
                      />
                    </div>

                    <div>
                      <Label htmlFor="positionY">Y অবস্থান (%)</Label>
                      <Input
                        id="positionY"
                        type="number"
                        min="0"
                        max="100"
                        value={customization.position.y}
                        onChange={(e) => setCustomization(prev => ({
                          ...prev,
                          position: { ...prev.position, y: Number(e.target.value) }
                        }))}
                      />
                    </div>
                  </div>
                </CardContent>
              </Card>

              {/* Action Buttons */}
              <div className="grid grid-cols-1 gap-3">
                <div className="flex gap-3">
                  <Button
                    className="flex-1 bg-orange-500 hover:bg-orange-600 text-white"
                    onClick={handleAddToCart}
                  >
                    <ShoppingCart className="w-4 h-4 mr-2" />
                    কার্টে যোগ করুন
                  </Button>

                  <Button
                    className="flex-1 bg-green-600 hover:bg-green-700 text-white"
                    onClick={() => setIsOrderNowOpen(true)}
                  >
                    <Zap className="w-4 h-4 mr-2" />
                    অর্ডার করুন
                  </Button>
                </div>

                <Button
                  variant="outline"
                  className="w-full border-orange-500 text-orange-600 hover:bg-orange-50"
                  onClick={() => setLocation('/contact')}
                >
                  <Heart className="w-4 h-4 mr-2" />
                  সাহায্য চান
                </Button>
              </div>
            </div>
          </div>
        </div>

        {/* Order Now Modal */}
        <OrderNowModal
          isOpen={isOrderNowOpen}
          onClose={() => setIsOrderNowOpen(false)}
          product={product}
          customization={customization}
        />
      </div>
    </MobileOptimizedLayout>
  );
}

