  minPrice: 0,
  maxPrice: 10000,
  inStock: false,
  featured: false,
  sortBy: 'featured',
  sortOrder: 'desc'
};

const SORT_OPTIONS = [
  { value: 'featured-desc', label: 'ফিচার্ড পণ্য আগে', icon: Star },
  { value: 'newest-desc', label: 'নতুন পণ্য আগে', icon: Clock },
